import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GeneratedInteraction {
  id: string;
  name: string;
  prompt: string;
  html: string;
  css: string;
  js: string;
  timestamp: number;
  variationOf?: string;
}

export interface GenerationResponse {
  name: string;
  html: string;
  css: string;
  js: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the micro-interaction",
    },
    html: {
      type: Type.STRING,
      description: "The HTML structure (using Tailwind classes where possible)",
    },
    css: {
      type: Type.STRING,
      description: "Additional CSS required for animations or custom styling",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string
): Promise<GenerationResponse> => {
  const systemInstruction = `
    You are a world-class Frontend Engineer and UI/UX Designer. 
    Your task is to create a "micro-interaction" - a single, beautiful, interactive UI component.
    Examples: 3D flip cards, liquid buttons, morphing loaders, hover-animated navigation, etc.

    Guidelines:
    - Use Tailwind CSS for the majority of styling.
    - Provide raw CSS only for things Tailwind cannot easily do (like complex keyframes or gradients).
    - Provide Vanilla JS for any state or animation triggers.
    - The HTML should be self-contained (wrapped in a div with an ID like 'interaction-root').
    - The design should be modern, clean, and "Apple-esque" or "Notion-esque".
  `;

  const userPrompt = context 
    ? `Based on this previous interaction: "${context}", generate a new variation or refinement according to this instruction: "${prompt}"`
    : `Create a beautiful micro-interaction based on: "${prompt}"`;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: userPrompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  return JSON.parse(response.text.trim());
};

import React, { useEffect, useRef } from 'react';
import { GeneratedInteraction } from '../types';

interface InteractionPreviewProps {
  interaction: GeneratedInteraction;
}

const InteractionPreview: React.FC<InteractionPreviewProps> = ({ interaction }) => {
  const iframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    if (iframeRef.current) {
      const doc = iframeRef.current.contentDocument;
      if (doc) {
        const fullContent = `
          <!DOCTYPE html>
          <html>
            <head>
              <script src="https://cdn.tailwindcss.com"></script>
              <style>
                body { margin: 0; display: flex; align-items: center; justify-content: center; min-height: 100vh; background: transparent; overflow: hidden; }
                ${interaction.css}
              </style>
            </head>
            <body>
              ${interaction.html}
              <script>
                (function() {
                  try {
                    ${interaction.js}
                  } catch (e) {
                    console.error('Interaction Error:', e);
                  }
                })();
              </script>
            </body>
          </html>
        `;
        doc.open();
        doc.write(fullContent);
        doc.close();
      }
    }
  }, [interaction]);

  return (
    <div className="w-full h-[500px] bg-gray-50 rounded-xl border border-gray-100 flex items-center justify-center overflow-hidden relative">
      <iframe
        ref={iframeRef}
        title="Interaction Preview"
        className="w-full h-full border-none"
      />
    </div>
  );
};

export default InteractionPreview;

import React, { useState } from 'react';

interface CodeBlockProps {
  code: string;
  language: string;
}

const CodeBlock: React.FC<CodeBlockProps> = ({ code, language }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(code);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="relative group rounded-lg overflow-hidden bg-gray-900 border border-gray-800">
      <div className="flex items-center justify-between px-4 py-2 bg-gray-800 border-b border-gray-700">
        <span className="text-xs font-mono text-gray-400 uppercase tracking-wider">{language}</span>
        <button
          onClick={handleCopy}
          className="text-xs text-gray-400 hover:text-white transition-colors"
        >
          {copied ? 'Copied!' : 'Copy'}
        </button>
      </div>
      <pre className="p-4 overflow-x-auto notion-scrollbar">
        <code className="text-sm font-mono text-gray-300">
          {code}
        </code>
      </pre>
    </div>
  );
};

export default CodeBlock;

import React, { useState, useEffect, useCallback } from 'react';
