                    type="text"
                    placeholder="Ask for changes (e.g., 'Make it blue', 'Add more bounce')..."
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-gray-100 bg-white"
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
