import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the micro-interaction",
    },
    html: {
      type: Type.STRING,
      description: "The HTML structure. Ensure every element referenced in JS has a unique ID.",
    },
    css: {
      type: Type.STRING,
      description: "Additional CSS for animations, gradients, or complex states.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript. Do not use external modules. Reference elements by the IDs provided in the HTML.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const systemInstruction = `
    You are a world-class Frontend Engineer and UI Designer specialized in micro-interactions.
    Your goal is to output a single interactive component using HTML, Tailwind CSS, and Vanilla JS.

    CRITICAL RULES:
    1. Only use Tailwind CSS (CDN is provided in the runner).
    2. Write Vanilla JS. NO ES MODULE IMPORTS. 
    3. Ensure the JS runs after the DOM is ready. 
    4. IDs used in JS MUST match IDs in HTML exactly.
    5. The interaction should be centered and responsive.
    6. Design style: Clean, Modern, Apple-like, or high-end SaaS (Notion/Linear).
    7. NO external images/assets unless from a reliable placeholder like Unsplash/Lucide (via SVG).
  `;

  const userText = context 
    ? `Current Code Context: ${context}. Instruction: ${prompt}. REGENERATE full updated code.`
    : `Create a beautiful micro-interaction for: ${prompt}`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  return JSON.parse(response.text.trim());
};

import React, { useState, useRef } from 'react';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setAttachedImage({
          data: base64String,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAttachment = () => {
    setAttachedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}, CSS: ${activeInteraction.css}, JS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name,
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        variationOf: activeId || undefined,
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) setPrompt('');
      removeAttachment();
    } catch (error) {
      console.error("Generation failed:", error);
      alert("Failed to generate interaction. Check your API key or prompt.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNewInteraction = () => {
    setActiveId(null);
    setPrompt('');
    removeAttachment();
  };

  const copyFullCode = () => {
    if (!activeInteraction) return;
    const fullHtml = `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${activeInteraction.name}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <style>
        body { margin: 0; display: flex; align-items: center; justify-content: center; min-height: 100vh; background: #f8fafc; }
        ${activeInteraction.css}
    </style>
</head>
<body>
    ${activeInteraction.html}
    <script>
        (function() {
            try {
                ${activeInteraction.js}
            } catch (e) {
                console.error('Script Error:', e);
            }
        })();
    </script>
</body>
</html>`;
    navigator.clipboard.writeText(fullHtml);
    alert('Full self-contained HTML copied to clipboard!');
  };

  return (
    <div className="flex h-screen bg-white text-gray-900 overflow-hidden">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={handleFileUpload} 
      />

      {/* Sidebar */}
      <aside className={`${sidebarOpen ? 'w-64' : 'w-0'} transition-all duration-300 ease-in-out flex flex-col border-r border-gray-100 bg-[#fbfbfa] shrink-0 overflow-hidden`}>
        <div className="p-4 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-gray-900 rounded flex items-center justify-center">
              <span className="text-white text-[10px] font-bold">MN</span>
            </div>
            <span className="text-sm font-semibold text-gray-700">Workspace</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="text-gray-400 hover:text-gray-600">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 19l-7-7 7-7m8 14l-7-7 7-7" /></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-2">
          <button
            onClick={handleNewInteraction}
            className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-500 hover:bg-gray-100 rounded-md mb-6 transition-colors group"
          >
            <div className="w-5 h-5 flex items-center justify-center rounded border border-dashed border-gray-300 group-hover:border-gray-400 text-gray-400">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
            </div>
            <span>New Interaction</span>
          </button>

          <div className="px-2 mb-2">
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">History</span>
          </div>
          <div className="space-y-0.5">
            {history.map(item => (
              <button
                key={item.id}
                onClick={() => setActiveId(item.id)}
                className={`w-full text-left px-3 py-1.5 rounded-md text-sm flex items-center gap-2 transition-all ${activeId === item.id ? 'bg-gray-200 text-gray-900 font-medium' : 'text-gray-600 hover:bg-gray-100'}`}
              >
                <div className="w-1.5 h-1.5 rounded-full bg-gray-300"></div>
                <span className="truncate flex-1">{item.name}</span>
                {item.hasImage && <div className="w-1 h-1 rounded-full bg-blue-400"></div>}
              </button>
            ))}
          </div>
        </div>
      </aside>

      {/* Main Container */}
      <main className="flex-1 flex flex-col min-w-0 bg-white relative">
        <header className="h-12 border-b border-gray-100 flex items-center justify-between px-4 sticky top-0 bg-white z-20">
          <div className="flex items-center gap-4">
            {!sidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="text-gray-400 hover:text-gray-600 p-1">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" /></svg>
              </button>
            )}
            <div className="flex items-center text-xs text-gray-400 gap-1.5">
              <button onClick={handleNewInteraction} className="hover:text-gray-700">Library</button>
              <span>/</span>
              <span className="text-gray-800 font-medium truncate max-w-[200px]">{activeInteraction?.name || 'New'}</span>
            </div>
          </div>

          {activeInteraction && (
            <div className="flex items-center gap-3">
              <button onClick={copyFullCode} className="text-xs text-gray-500 hover:text-gray-900 flex items-center gap-1.5 px-2 py-1 hover:bg-gray-50 rounded">
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                Copy All-in-One
              </button>
              <div className="h-4 w-[1px] bg-gray-200"></div>
              <div className="flex items-center gap-1 bg-gray-100 p-0.5 rounded-lg">
                <button
                  onClick={() => setViewMode('preview')}
                  className={`px-3 py-1 text-xs rounded-md transition-all ${viewMode === 'preview' ? 'bg-white shadow-sm text-gray-900 font-medium' : 'text-gray-500 hover:text-gray-700'}`}
                >Preview</button>
                <button
                  onClick={() => setViewMode('code')}
                  className={`px-3 py-1 text-xs rounded-md transition-all ${viewMode === 'code' ? 'bg-white shadow-sm text-gray-900 font-medium' : 'text-gray-500 hover:text-gray-700'}`}
                >Code</button>
              </div>
            </div>
          )}
        </header>

        <div className="flex-1 overflow-y-auto p-4 md:p-10 max-w-6xl mx-auto w-full notion-scrollbar">
          {!activeInteraction ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-8 max-w-xl mx-auto">
