import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

// Always initialize inside the function or use a getter to ensure the latest API key is used
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, creative name for the micro-interaction (e.g., 'Liquid Gravity Button')",
    },
    html: {
      type: Type.STRING,
      description: "The HTML structure. Include all necessary IDs used by the JavaScript.",
    },
    css: {
      type: Type.STRING,
      description: "CSS for animations and custom styling. Use Tailwind classes in the HTML as much as possible, use this for custom keyframes or complex effects.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Do NOT use modules or external imports. Reference IDs exactly as they appear in the HTML.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a master of web micro-interactions. Your task is to generate a single, self-contained interactive component.

    GUIDELINES:
    - Use Tailwind CSS via CDN (already included in the preview).
    - Provide raw CSS only for complex animations, gradients, or masks that Tailwind can't handle.
    - JavaScript must be vanilla and NOT use 'import' or 'export'.
    - Ensure all IDs in the HTML are unique and match those used in the JavaScript.
    - The design must be premium: smooth easing, high-quality colors, and "juicy" feedback.
    - Avoid external assets. Use inline SVGs if icons are needed.
    - The code should be ready to drop into a standard HTML file.
  `;

  const userText = context 
    ? `Current component code:\n${context}\n\nUser request: "${prompt}"\n\nPlease output the updated full code for the component.`
    : `Create a beautiful micro-interaction based on: "${prompt}"`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  return JSON.parse(text.trim());
};

