import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

// Always initialize inside the function or use a getter to ensure the latest API key is used
const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, creative name for the micro-interaction (e.g., 'Liquid Gravity Button')",
    },
    html: {
      type: Type.STRING,
      description: "The HTML structure. Include all necessary IDs used by the JavaScript.",
    },
    css: {
      type: Type.STRING,
      description: "CSS for animations and custom styling. Use Tailwind classes in the HTML as much as possible, use this for custom keyframes or complex effects.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Do NOT use modules or external imports. Reference IDs exactly as they appear in the HTML.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a master of web micro-interactions and high-end UI/UX design. Your task is to generate a single, professional, self-contained interactive component.

    GUIDELINES:
    - Framework: Vanilla HTML + Tailwind CSS (via CDN) + Vanilla JS.
    - Style: Premium, clean, "Apple-esque" or "Notion/Linear" aesthetic. Focus on motion, easing, and micro-feedback.
    - JS Rules: 
      1. Reference elements by ID. 
      2. No imports/exports. 
      3. No external libraries. 
      4. Ensure all logic is self-contained.
    - HTML Rules: 
      1. Keep it concise. 
      2. Use Tailwind for layout and standard styling.
    - CSS Rules: 
      1. Use for keyframes, complex gradients, or layout tricks Tailwind can't easily do.
    - Consistency: The ID used in JS must exist in the HTML.
  `;

  const userText = context 
    ? `Current component code:\n${context}\n\nUser request: "${prompt}"\n\nPlease output the updated full code for the component. Ensure HTML, CSS, and JS are perfectly synced.`
    : `Create a beautiful micro-interaction based on: "${prompt}"`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("Failed to parse JSON:", text);
    throw new Error("AI returned invalid JSON. Please try again.");
  }
};

