import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the micro-interaction (e.g., 'Nordic Relief Weather')",
    },
    html: {
      type: Type.STRING,
      description: "The HTML structure. Use Tailwind classes for the layout. Ensure IDs match JS references.",
    },
    css: {
      type: Type.STRING,
      description: "Advanced CSS: Neumorphic box-shadows, relief effects, keyframe animations, and custom typography setup.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for tilt effects, state changes, or physics-based animations. No external modules.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist. Your goal is to generate "Production-Ready Micro-Interactions" that are visually stunning and interactive.

    DESIGN PHILOSOPHY (Sanded Alabaster / Relief UI):
    - Use "relief" effects: inset shadows for recessed elements, outer shadows for raised elements.
    - Colors: Soft, natural palettes (Alabaster, Bone, Mist, Charcoal).
    - Texture: Subtle grain/noise overlays (provided in the environment).
    - Typography: Use 'Inter' for body and 'JetBrains Mono' for technical/data labels.
    - Animation: High-frequency interactions like "Gentle Tilt" (mousemove) or "Scale on Hover".

    TECHNICAL RULES:
    1. Framework: Tailwind CSS + Vanilla JS.
    2. Self-Contained: No external image files or fonts (the environment provides Inter and JetBrains Mono).
    3. Icons: Use raw SVG code or Lucide-style simple SVGs.
    4. Code Structure: The JS should target specific IDs defined in the HTML.
    5. Layout: Ensure the component is responsive but ideally designed for a focused "Stage" area (max-width 440px-600px).
    6. Performance: Keep animations hardware-accelerated (transform, opacity).

    The user wants "Juice". Provide code that feels tactile, premium, and "sculpted" out of the page surface.
  `;

  const userText = context 
    ? `Update this component:\n${context}\n\nChange requested: "${prompt}"\n\nEnsure the updated output is a complete, polished, and fully synced component.`
    : `Create a world-class micro-interaction: "${prompt}". Focus on the relief-style UI and smooth interactivity.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

