import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, descriptive name for the interaction",
    },
    html: {
      type: Type.STRING,
      description: "Complete HTML structure. Use unique IDs for any element the JS needs to interact with.",
    },
    css: {
      type: Type.STRING,
      description: "CSS for animations, transitions, and custom styling. Use Tailwind classes in the HTML when possible.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Must be self-contained and use the IDs defined in the HTML.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist at a top design studio. 
    Your goal is to build stunning, high-performance web micro-interactions.

    CORE REQUIREMENTS:
    - Framework: Tailwind CSS + Vanilla JS.
    - Interactivity: Components MUST be interactive. Use JS for hover states, clicks, drag effects, or physics if appropriate.
    - Aesthetics: Aim for a "premium" feel. This could be Apple-like minimalism, Bento-style layouts, 3D relief, or Glassmorphism—whatever fits the prompt best.
    - Accuracy: Pay extreme attention to the user's specific request. If they ask for a change, prioritize that change while keeping the rest of the component polished.
    - Self-Contained: No external scripts, modules, or assets. Use inline SVG for icons.

    TIPS FOR "JUICE":
    - Use spring-based timing for transitions.
    - Add subtle feedback (shadow shifts, scale changes, color glows).
    - Ensure fonts are readable and layouts are centered.
  `;

  const userText = context 
    ? `You are updating an existing component. 
       Current Code Context:
       ${context}

       Update Instruction: "${prompt}"

       Provide the FULL updated code (HTML, CSS, JS) that implements this change.`
    : `Create a new, stunning micro-interaction for: "${prompt}"`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

