import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, descriptive name for the interaction",
    },
    html: {
      type: Type.STRING,
      description: "Complete HTML structure. Use unique IDs for elements the JS targets.",
    },
    css: {
      type: Type.STRING,
      description: "Advanced CSS: Gradients, blurs, realistic shadows, glassmorphism, and custom animations.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Must be self-contained and use the IDs defined in the HTML.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Senior Creative Technologist specializing in high-fidelity, realistic web micro-interactions.
    Your goal is to transform text prompts and reference images into stunning, interactive UI components.

    VISUAL FIDELITY RULES:
    - If the user asks for "realistic" or "high-fidelity", use multi-layered box-shadows, complex linear/radial gradients, and backdrop-filters (glassmorphism).
    - Texture: Use inline SVG filters within the HTML to create realistic noise, grain, or paper textures if the prompt implies a physical material.
    - Lighting: Simulate global illumination using subtle highlights (top/left) and deep shadows (bottom/right).
    - Faithful Execution: If an image is provided, analyze its color palette, lighting direction, corner radii, and overall "vibe" and replicate it precisely.
    - Typography: Use "Inter" for UI and "JetBrains Mono" for technical data.

    INTERACTIVE RULES:
    - Juice: Use physics-based motion (springs) or high-quality cubic-bezier curves (e.g., [0.16, 1, 0.3, 1]).
    - Feedback: Every interaction (hover, click, focus) must have a visual response (e.g., scaling, shadow shift, subtle glow).
    - Framework: Use Tailwind CSS for basic layout but rely on raw CSS for advanced effects like glassmorphism or custom shaders.
    - Vanilla JS: No external libraries. Reference elements by ID.

    If updating an existing component, preserve the high-quality aesthetic while strictly implementing the requested changes.
  `;

  const userText = context 
    ? `Update this high-fidelity component.
       Existing Code:
       ${context}

       Update Request: "${prompt}"

       Provide the FULL updated code. Maintain or improve the visual fidelity, gradients, blurs, and realism.`
    : `Generate a stunning, high-fidelity micro-interaction based on: "${prompt}". Use advanced CSS for realism (blurs, textures, materials).`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

