import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the component (e.g., 'Frosted Obsidian Card')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Include unique IDs for JS hooks.",
    },
    css: {
      type: Type.STRING,
      description: "Advanced CSS: backdrop-filter, linear-gradients, radial-highlights, and multi-layered box-shadows. Use raw CSS for realism.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Implement tactile feedback (hover/click) and smooth motion.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist. Your specialty is "Hyper-Realistic Web Micro-Interactions".

    VISUAL FIDELITY PROTOCOL:
    - Realism: Use multi-layered shadows (diffuse + sharp) to simulate depth. 
    - Materials: If asked for 'realistic', simulate glass (backdrop-filter: blur), metal (brushed gradients), or paper (inline SVG noise textures).
    - Lighting: Always define a light source (usually top-left). Add white 1px borders (highlights) on top/left and dark borders (shadows) on bottom/right.
    - Reference Faithful: If an image is provided, replicate its corner radii, blur intensity, and color temperature exactly.
    - Typography: UI uses 'Inter'. Numbers/Technical data use 'JetBrains Mono'.

    INTERACTION PROTOCOL:
    - Motion: Use cubic-bezier(0.16, 1, 0.3, 1) for 'spring-like' snap.
    - Hover: Elements should scale slightly (1.02x) and increase shadow depth.
    - Click: Elements should scale down (0.98x) and shift shadow to 'inset'.

    TECHNICAL:
    - Framework: Tailwind for layout, raw CSS for 'juice' (blurs, glass, gradients).
    - Self-Contained: No external assets. Use SVG for all icons.
  `;

  const userText = context 
    ? `Current Component Status:
       ${context}

       Refinement: "${prompt}"

       Maintain the existing high-fidelity materials and blurs. Update the code to implement the new request while preserving the realistic aesthetic.`
    : `Build a hyper-realistic micro-interaction: "${prompt}". Focus on lighting, material textures (glass/grain), and tactile feedback.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 4000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

