                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2.5" strokeLinecap="round"/></svg>
                    </button>
                  </div>
                  <input
                    id="refinement-input"
                    type="text"
                    placeholder="E.g., 'Make it sharper', 'Increase motion springiness'..."
                    className="flex-1 px-5 py-5 bg-transparent border-none focus:outline-none text-gray-700 font-medium placeholder-gray-300 text-lg"
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
                        const val = (e.target as HTMLInputElement).value;
                        handleGenerate(val);
                        (e.target as HTMLInputElement).value = '';
                      }
                    }}
                  />
                  <div className="flex items-center shrink-0">
                    <button 
                      onClick={() => {
                        const input = document.getElementById('refinement-input') as HTMLInputElement;
                        handleGenerate(input.value);
                        input.value = '';
                      }}
