                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7m0 0l-7 7m7-7H3" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    </button>
                  </div>
                </div>
                {attachedImage && (
                  <div className="mt-4 flex items-center gap-2">
                    <button onClick={removeAttachment} className="text-[10px] text-red-400 hover:text-red-600 font-bold uppercase tracking-widest transition-all flex items-center gap-2 px-3 py-1 bg-red-50 rounded-lg">
                      Clear image override
