import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the component (e.g., 'Modern Glass Toggle')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Include unique IDs for JS hooks.",
    },
    css: {
      type: Type.STRING,
      description: "Standard CSS for all styling. DO NOT use Tailwind classes in HTML; put all styling here to ensure portability.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Implement tactile feedback (hover/click) and smooth motion.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist. Your specialty is "Hyper-Realistic Web Micro-Interactions".

    STRICT VISUAL RULES:
    1. PROMPT FAITHFULNESS: ONLY add "grain", "noise", "texture", or "paper" effects if the user explicitly asks for them.
    2. CLEAN BACKGROUNDS: The component should be centered on a clean background. Do NOT add complex environmental backgrounds (gradients, patterns, images) unless explicitly requested.
    3. PORTABILITY (CRITICAL): Style everything using standard CSS in the "css" field. Avoid using Tailwind classes (like 'bg-blue-500' or 'rounded-xl') in the HTML. This ensures the component can be exported as a standalone SVG.
    4. FIDELITY: Use multi-layered shadows and 1px highlights to simulate depth. 
    5. MATERIALS: If 'glass' is asked for, use backdrop-filter: blur.

    INTERACTION PROTOCOL:
    - Motion: Use cubic-bezier(0.16, 1, 0.3, 1) for a high-end feel.
    - Tactile Feedback: Every interaction (hover, click) must have a visual response.

    TECHNICAL:
    - Framework: Use Standard CSS for the component styles. No external assets. Icons must be inline SVGs.
  `;

  const userText = context 
    ? `Current Component Code:
       ${context}

       Update Request: "${prompt}"

       Instructions: Maintain a clean aesthetic. Style the component using ONLY the CSS field to ensure it works when exported to SVG. Remove Tailwind classes from the HTML.`
    : `Build a micro-interaction: "${prompt}". Focus on clean rendering and smooth motion. Style exclusively with CSS in the CSS block (no Tailwind in HTML) to ensure SVG export compatibility.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

import React, { useState, useRef } from 'react';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  const getFullHtml = (interaction: GeneratedInteraction) => {
    return `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${interaction.name}</title>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet">
    <style>
        body { 
            margin: 0; 
            display: flex; 
            align-items: center; 
            justify-content: center; 
            min-height: 100vh; 
            background: #ffffff; 
            font-family: 'Inter', sans-serif;
            overflow: hidden;
            -webkit-font-smoothing: antialiased;
        }
        ${interaction.css}
    </style>
</head>
<body>
    <div id="root">
        ${interaction.html}
    </div>

    <script type="module">
        (function() {
            try {
                ${interaction.js}
            } catch (e) {
                console.error('Interaction Script Error:', e);
            }
        })();
    </script>
</body>
</html>`;
  };

  const downloadAsSvg = () => {
    if (!activeInteraction) return;

    const width = 800;
    const height = 600;

    // Construct the SVG string with foreignObject to capture the HTML/CSS
    // Using a more robust container structure for the SVG export
    const svgString = `
<svg width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" fill="none" xmlns="http://www.w3.org/2000/svg">
  <rect width="${width}" height="${height}" fill="white"/>
  <foreignObject width="100%" height="100%">
    <div xmlns="http://www.w3.org/1999/xhtml" style="width: ${width}px; height: ${height}px; display: flex; align-items: center; justify-content: center; font-family: sans-serif; -webkit-font-smoothing: antialiased;">
      <style>
        /* Embedded Component Styles */
        ${activeInteraction.css}

        #interaction-root {
          display: flex;
          align-items: center;
          justify-content: center;
          perspective: 1200px;
        }
      </style>
      <div id="interaction-root">
        ${activeInteraction.html}
      </div>
    </div>
  </foreignObject>
</svg>`.trim();

    const blob = new Blob([svgString], { type: 'image/svg+xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${activeInteraction.name.replace(/\s+/g, '-').toLowerCase()}.svg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setAttachedImage({
          data: base64String,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAttachment = () => {
    setAttachedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Interaction',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        variationOf: activeId || undefined,
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) setPrompt('');
      removeAttachment();
    } catch (error: any) {
      console.error("Generation failed:", error);
      alert(`Error: ${error.message || 'Failed to generate interaction.'}`);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNewInteraction = () => {
    setActiveId(null);
    setPrompt('');
    removeAttachment();
  };

  return (
    <div className="flex h-screen bg-white text-gray-900 overflow-hidden font-sans relative">
