        <div className="p-4 flex items-center justify-between border-b border-gray-50 bg-white">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-black rounded shadow-sm flex items-center justify-center">
              <span className="text-white text-[10px] font-bold">MN</span>
            </div>
            <span className="text-sm font-bold tracking-tight">MicroNotion</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="text-gray-400 hover:text-gray-600 p-1">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 19l-7-7 7-7m8 14l-7-7 7-7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-2 notion-scrollbar">
          <button onClick={handleNewInteraction} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-500 hover:bg-gray-100 rounded-lg mb-6 transition-all group">
            <div className="w-5 h-5 flex items-center justify-center rounded border border-dashed border-gray-300 text-gray-400 group-hover:border-gray-400 group-hover:text-gray-600">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </div>
            <span className="font-medium">New Creation</span>
          </button>

          <div className="px-3 mb-2">
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">History</span>
          </div>
          <div className="space-y-0.5">
            {history.map(item => (
              <button
                key={item.id}
                onClick={() => setActiveId(item.id)}
                className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-all truncate flex items-center justify-between group ${activeId === item.id ? 'bg-gray-200 text-gray-900 font-semibold shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
