    name: {
      type: Type.STRING,
      description: "A creative name for the component (e.g., 'Modern Glass Toggle')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Include unique IDs for JS hooks.",
    },
    css: {
      type: Type.STRING,
      description: "Standard CSS for all styling. DO NOT use Tailwind classes in HTML; put all styling here to ensure portability and high fidelity.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Implement tactile feedback (hover/click) and smooth motion.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist. Your specialty is "Hyper-Realistic Web Micro-Interactions".

    STRICT VISUAL RULES:
    1. PROMPT FAITHFULNESS: ONLY add "grain", "noise", "texture", or "paper" effects if the user explicitly asks for them.
    2. CLEAN BACKGROUNDS: The component should be centered on a clean background. Do NOT add complex environmental backgrounds (gradients, patterns, images) unless explicitly requested.
    3. PORTABILITY: Style everything using standard CSS in the "css" field. Avoid using Tailwind classes (like 'bg-blue-500' or 'rounded-xl') in the HTML. 
    4. FIDELITY: Use multi-layered shadows and 1px highlights to simulate depth. 
    5. MATERIALS: If 'glass' is asked for, use backdrop-filter: blur.

    INTERACTION PROTOCOL:
    - Motion: Use cubic-bezier(0.16, 1, 0.3, 1) for a high-end feel.
    - Tactile Feedback: Every interaction (hover, click) must have a visual response.

    TECHNICAL:
    - Framework: Use Standard CSS for the component styles. No external assets. Icons must be inline SVGs.
  `;

  const userText = context 
    ? `Current Component Code:
       ${context}

       Update Request: "${prompt}"

       Instructions: Maintain a clean aesthetic. Style the component using ONLY the CSS field to ensure maximum fidelity. Remove Tailwind classes from the HTML.`
    : `Build a micro-interaction: "${prompt}". Focus on clean rendering and smooth motion. Style exclusively with CSS in the CSS block (no Tailwind in HTML) for maximum polish.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

import React, { useState, useRef } from 'react';
import { generateInteraction } from './services/geminiService';
