  { label: 'Matte Plastic', prompt: 'Soft matte plastic texture with very subtle highlights.' },
  { label: 'Brushed Aluminum', prompt: 'Horizontal metallic grain texture with anisotropic highlights.' },
  { label: 'Holographic', prompt: 'Iridescent color-shifting finish that reacts to "light".' },
  { label: 'Mesh Gradient', prompt: 'Background with soft, multi-colored mesh gradient textures.' },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [inspectorOpen, setInspectorOpen] = useState(true);
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);
  const [materialSearch, setMaterialSearch] = useState('');
  const [isMaterialDropdownOpen, setIsMaterialDropdownOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  const filteredMaterials = useMemo(() => 
    MATERIAL_OPTIONS.filter(m => m.label.toLowerCase().includes(materialSearch.toLowerCase())),
    [materialSearch]
  );

  const getFullHtml = (interaction: GeneratedInteraction) => {
    return `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${interaction.name}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet">
    <style>
        body { 
            margin: 0; 
            display: flex; 
            align-items: center; 
            justify-content: center; 
            min-height: 100vh; 
            background: #ffffff; 
            font-family: 'Inter', sans-serif;
            overflow: hidden;
        }
        ${interaction.css}
    </style>
</head>
<body>
    <div id="root">
        ${interaction.html}
    </div>

    <script type="module">
        (function() {
            try {
                ${interaction.js}
            } catch (e) {
                console.error('Interaction Script Error:', e);
            }
        })();
    </script>
</body>
</html>`;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setAttachedImage({
          data: base64String,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAttachment = () => {
    setAttachedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Interaction',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        variationOf: activeId || undefined,
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) setPrompt('');
      removeAttachment();
    } catch (error: any) {
      console.error("Generation failed:", error);
      alert(`Error: ${error.message || 'Failed to generate interaction.'}`);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNewInteraction = () => {
    setActiveId(null);
    setPrompt('');
    removeAttachment();
  };

  return (
    <div className="flex h-screen bg-white text-gray-900 overflow-hidden font-sans relative">
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />

      {/* 1. Sidebar (Explorer) */}
      <aside className={`${sidebarOpen ? 'w-64' : 'w-0'} transition-all duration-300 flex flex-col border-r border-gray-100 bg-[#fbfbfa] shrink-0 overflow-hidden z-10`}>
        <div className="p-4 flex items-center justify-between border-b border-gray-50 bg-white">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-black rounded shadow-sm flex items-center justify-center">
              <span className="text-white text-[10px] font-bold">MN</span>
            </div>
            <span className="text-sm font-bold tracking-tight">MicroNotion</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="text-gray-400 hover:text-gray-600 p-1">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 19l-7-7 7-7m8 14l-7-7 7-7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-2 notion-scrollbar">
          <button onClick={handleNewInteraction} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-500 hover:bg-gray-100 rounded-lg mb-6 transition-all group">
            <div className="w-5 h-5 flex items-center justify-center rounded border border-dashed border-gray-300 text-gray-400 group-hover:border-gray-400 group-hover:text-gray-600">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </div>
            <span className="font-medium">New Creation</span>
          </button>

          <div className="px-3 mb-2">
            <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">History</span>
          </div>
          <div className="space-y-0.5">
            {history.map(item => (
              <button
                key={item.id}
                onClick={() => setActiveId(item.id)}
                className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-all truncate flex items-center justify-between group ${activeId === item.id ? 'bg-gray-200 text-gray-900 font-semibold shadow-sm' : 'text-gray-500 hover:bg-gray-100'}`}
              >
                <span className="truncate">{item.name}</span>
                {item.hasImage && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full shrink-0 ml-2"></div>}
              </button>
            ))}
          </div>
        </div>
      </aside>

      {/* 2. Main Workspace (Canvas) */}
      <main className="flex-1 flex flex-col min-w-0 bg-white relative z-0">
        <header className="h-12 border-b border-gray-100 flex items-center justify-between px-4 sticky top-0 bg-white/80 backdrop-blur-md z-20">
          <div className="flex items-center gap-4">
            {!sidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="text-gray-400 hover:text-gray-600 p-1">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 6h16M4 12h16M4 18h16" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
            )}
            <div className="flex items-center text-[11px] font-mono text-gray-400 gap-1.5 uppercase tracking-wider">
              <span>Workspace</span>
              <span>/</span>
              <span className="text-black font-bold truncate max-w-[200px]">{activeInteraction?.name || 'Creation Lab'}</span>
            </div>
          </div>

          {activeInteraction && (
            <div className="flex items-center gap-3">
              <div className="flex items-center gap-1 bg-gray-100 p-0.5 rounded-lg border border-gray-200/50 shadow-sm">
                <button
                  onClick={() => setViewMode('preview')}
                  className={`px-3 py-1 text-[11px] rounded-md transition-all font-bold ${viewMode === 'preview' ? 'bg-white shadow-sm text-black' : 'text-gray-500 hover:text-gray-700'}`}
                >Preview</button>
                <button
                  onClick={() => setViewMode('code')}
                  className={`px-3 py-1 text-[11px] rounded-md transition-all font-bold ${viewMode === 'code' ? 'bg-white shadow-sm text-black' : 'text-gray-500 hover:text-gray-700'}`}
                >Full Code</button>
              </div>
              {!inspectorOpen && (
                 <button onClick={() => setInspectorOpen(true)} className="text-gray-400 hover:text-gray-600 p-1">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                 </button>
              )}
            </div>
          )}
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 max-w-5xl mx-auto w-full notion-scrollbar">
          {!activeInteraction ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
              <div className="w-20 h-20 bg-[#fbfbfa] rounded-[32px] flex items-center justify-center text-4xl shadow-inner border border-gray-100">✨</div>
              <div className="space-y-4">
                <h1 className="text-5xl font-black tracking-tighter text-black">Interaction Studio</h1>
                <p className="text-gray-400 text-lg max-w-lg mx-auto font-medium leading-relaxed">Describe a micro-interaction. Refine every detail visually.</p>
              </div>

              <div className="w-full max-w-xl space-y-6 pt-6">
                <div className="relative group bg-white shadow-2xl rounded-3xl p-2 border border-gray-100 flex items-center transition-all focus-within:ring-8 focus-within:ring-gray-50">
                  <div className="flex items-center shrink-0">
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className={`ml-2 p-4 rounded-2xl transition-all ${attachedImage ? 'bg-blue-50 text-blue-600 shadow-sm' : 'text-gray-300 hover:text-gray-600'}`}
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    </button>
                  </div>
                  <input
                    type="text"
                    placeholder="E.g., 'Modern glass switch with bounce'..."
                    className="flex-1 px-4 py-6 rounded-2xl border-none focus:outline-none bg-transparent text-xl font-medium placeholder-gray-200"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
                  />
                  <div className="flex items-center shrink-0 pr-1">
                    <button
                      onClick={() => handleGenerate()}
                      disabled={isGenerating || (!prompt.trim() && !attachedImage)}
                      className="p-5 bg-black text-white rounded-2xl disabled:opacity-30 hover:bg-gray-800 transition-all active:scale-95 shadow-xl flex items-center justify-center"
                    >
                      {isGenerating ? (
                        <svg className="animate-spin h-6 w-6" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" /></svg>
                      ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7m0 0l-7 7m7-7H3" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      )}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-12 animate-in fade-in duration-500 pb-32">
              <div className="flex items-end justify-between gap-8 flex-wrap">
                <div className="max-w-2xl space-y-3">
                  <h1 className="text-4xl font-black tracking-tight leading-none text-black">{activeInteraction.name}</h1>
                  <p className="text-gray-400 text-sm italic font-medium">"{activeInteraction.prompt}"</p>
                </div>
              </div>

              {viewMode === 'preview' ? (
                <div className="relative rounded-[40px] overflow-hidden shadow-[0_40px_80px_-20px_rgba(0,0,0,0.1)] border border-gray-100 bg-white">
                  <InteractionPreview interaction={activeInteraction} />
                </div>
              ) : (
                <div className="space-y-6 animate-in slide-in-from-bottom-6 duration-400">
                  <CodeBlock language="Single-File Component" code={getFullHtml(activeInteraction)} />
                </div>
              )}
            </div>
          )}
        </div>

        {isGenerating && (
          <div className="absolute inset-0 bg-white/60 backdrop-blur-xl z-50 flex items-center justify-center">
             <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-gray-100 border-t-black rounded-full animate-spin"></div>
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Applying Changes</p>
             </div>
          </div>
        )}
      </main>

      {/* 3. Right Sidebar (Inspector) */}
      {activeInteraction && (
        <aside className={`${inspectorOpen ? 'w-[320px]' : 'w-0'} transition-all duration-300 border-l border-gray-100 bg-[#fbfbfa] flex flex-col shrink-0 overflow-hidden z-10`}>
          <div className="p-4 flex items-center justify-between border-b border-gray-50 bg-white">
            <span className="text-[11px] font-bold text-gray-400 uppercase tracking-widest">Inspector</span>
            <button onClick={() => setInspectorOpen(false)} className="text-gray-400 hover:text-gray-600 p-1">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7m0 0l-7 7m7-7H3" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" transform="scale(-1,1) translate(-24,0)"/></svg>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 space-y-8 notion-scrollbar pb-10">
            {/* Manual Chat Refinement */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Manual Refinement</h4>
              <div className="relative group">
                <textarea
                  id="refinement-input-inspector"
                  placeholder="Describe changes (e.g. 'Add a pulsing effect')..."
                  className="w-full px-3 py-3 bg-white border border-gray-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-black/5 min-h-[80px] resize-none notion-scrollbar"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      const val = (e.target as HTMLTextAreaElement).value;
                      handleGenerate(val);
                      (e.target as HTMLTextAreaElement).value = '';
                    }
                  }}
                />
                <p className="text-[9px] text-gray-400 mt-1 font-medium">Press Enter to apply</p>
              </div>
            </section>

            {/* Theme Toggle */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Component Theme</h4>
              <div className="grid grid-cols-2 gap-2 p-1 bg-gray-100 rounded-xl">
                 <button 
                  onClick={() => handleGenerate('Switch the component to Light Mode style (light backgrounds, dark text).')}
                  className="flex items-center justify-center gap-2 py-2 px-3 bg-white shadow-sm rounded-lg text-[11px] font-bold hover:bg-white/80 transition-all border border-gray-200"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707.707M12 5a7 7 0 100 14 7 7 0 000-14z" strokeWidth="2" strokeLinecap="round"/></svg>
                  Light
                </button>
                 <button 
                  onClick={() => handleGenerate('Switch the component to Dark Mode style (dark backgrounds, light text).')}
                  className="flex items-center justify-center gap-2 py-2 px-3 bg-gray-900 text-white rounded-lg text-[11px] font-bold hover:bg-black transition-all shadow-sm"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z" strokeWidth="2" strokeLinecap="round"/></svg>
                  Dark
                </button>
              </div>
            </section>

            {/* Visual Styles */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Visual Style</h4>

              <div className="space-y-2">
                <label className="text-xs font-semibold text-gray-500">Theme Color</label>
                <div className="flex flex-wrap gap-2">
                  {[
                    {name: 'Obsidian', color: '#000000'},
                    {name: 'Iris', color: '#6366f1'},
                    {name: 'Emerald', color: '#10b981'},
                    {name: 'Rose', color: '#f43f5e'},
                    {name: 'Amber', color: '#f59e0b'},
                    {name: 'Violet', color: '#8b5cf6'}
                  ].map(c => (
                    <button 
                      key={c.name}
                      onClick={() => handleGenerate(`Change the primary theme color to ${c.color} (${c.name}).`)}
                      className="w-6 h-6 rounded-full border border-gray-200 transition-transform hover:scale-110 active:scale-95 shadow-sm"
                      style={{backgroundColor: c.color}}
                      title={c.name}
                    />
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-semibold text-gray-500">Corner Radius</label>
                <div className="grid grid-cols-3 gap-1 p-1 bg-gray-100 rounded-lg">
                  {['Sharp', 'Medium', 'Round'].map(r => (
                    <button 
                      key={r}
                      onClick={() => handleGenerate(`Set the border-radius to ${r === 'Sharp' ? '0px' : r === 'Medium' ? '12px' : '999px'}.`)}
                      className="text-[10px] font-bold py-1.5 px-2 rounded-md hover:bg-white hover:shadow-sm transition-all"
                    >{r}</button>
                  ))}
                </div>
              </div>
            </section>

            {/* Material Section - Searchable Dropdown */}
            <section className="space-y-4 relative">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Materiality</h4>
              <div className="relative">
                <div className="flex items-center bg-white border border-gray-200 rounded-xl px-3 py-2.5 shadow-sm focus-within:ring-2 focus-within:ring-black/5 transition-all">
                  <svg className="w-3.5 h-3.5 text-gray-400 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2.5"/></svg>
                  <input 
                    type="text" 
                    placeholder="Search materials..." 
                    className="w-full text-[11px] font-bold bg-transparent outline-none text-gray-700"
                    value={materialSearch}
                    onChange={(e) => {
                      setMaterialSearch(e.target.value);
                      setIsMaterialDropdownOpen(true);
                    }}
                    onFocus={() => setIsMaterialDropdownOpen(true)}
                  />
                  {materialSearch && (
                    <button onClick={() => setMaterialSearch('')} className="text-gray-300 hover:text-gray-500">
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3"/></svg>
                    </button>
                  )}
                </div>

                {isMaterialDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-100 rounded-xl shadow-2xl z-30 max-h-[200px] overflow-y-auto notion-scrollbar animate-in fade-in slide-in-from-top-2 duration-200">
                    {filteredMaterials.length > 0 ? (
                      filteredMaterials.map(m => (
                        <button
                          key={m.label}
                          onClick={() => {
                            handleGenerate(m.prompt);
                            setIsMaterialDropdownOpen(false);
                            setMaterialSearch('');
                          }}
                          className="w-full text-left px-4 py-3 text-[11px] font-bold text-gray-600 hover:bg-gray-50 hover:text-black border-b border-gray-50 last:border-0 transition-colors"
                        >
                          {m.label}
                        </button>
                      ))
                    ) : (
                      <div className="p-4 text-[10px] text-gray-400 font-bold text-center">No materials found</div>
                    )}
                  </div>
                )}

                {isMaterialDropdownOpen && (
                  <div className="fixed inset-0 z-20" onClick={() => setIsMaterialDropdownOpen(false)} />
                )}
              </div>
            </section>

            {/* Typography Section */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Typography</h4>
              <div className="flex items-center justify-between">
                <span className="text-xs font-semibold text-gray-500">Font Size</span>
                <div className="flex gap-1">
                  {['S', 'M', 'L'].map(sz => (
                    <button 
                      key={sz}
                      onClick={() => handleGenerate(`Adjust text sizing to ${sz === 'S' ? 'small/compact' : sz === 'M' ? 'standard' : 'large/hero'}.`)}
                      className="w-7 h-7 flex items-center justify-center bg-white border border-gray-200 rounded-md text-[10px] font-bold hover:border-black shadow-sm"
                    >{sz}</button>
                  ))}
                </div>
              </div>
            </section>

            {/* Physics Section */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Motion & Physics</h4>
              <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <label className="text-xs font-semibold text-gray-500">Speed</label>
                    <span className="text-[9px] font-bold text-gray-400 uppercase tracking-tighter">Snappy → Fluid</span>
                  </div>
                  <input 
                  type="range" 
                  min="1" max="10" 
                  className="w-full accent-black h-1 bg-gray-200 rounded-lg appearance-none cursor-pointer"
                  onChange={(e) => {
                    const val = parseInt(e.target.value);
                    if (val < 4) handleGenerate('Make the transitions much faster and snappier.');
                    else if (val > 7) handleGenerate('Make the transitions very slow and graceful.');
                    else handleGenerate('Set the transition speed to a balanced fluid pace.');
                  }}
                  />
              </div>
              <button 
                onClick={() => handleGenerate('Add a subtle "spring" bounce effect to all hover and active states.')}
                className="w-full py-2.5 bg-gray-900 text-white rounded-xl text-[11px] font-bold hover:bg-black transition-all shadow-lg active:scale-95"
              >
                Apply Spring Physics
              </button>
            </section>
          </div>

          <div className="p-4 bg-white border-t border-gray-50 mt-auto">
             <div className="bg-blue-50/50 rounded-xl p-3 border border-blue-100/50">
                <p className="text-[9px] font-bold text-blue-400 uppercase tracking-wider mb-1">AI Reasoning</p>
                <p className="text-[10px] text-blue-600 leading-tight">Gemini applies your constraints while maintaining structural design integrity.</p>
             </div>
          </div>
        </aside>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const MATERIAL_OPTIONS = [
  { label: 'Glassmorphism', prompt: 'Make it a glass container with backdrop blur and white border highlight.' },
  { label: 'Neumorphic', prompt: 'Apply a soft neumorphic look with inner and outer shadows.' },
  { label: 'Flat Solid', prompt: 'Clean solid fill with a 1px crisp border.' },
  { label: 'Frosted Glass', prompt: 'Heavy frosted glass effect with high blur and subtle noise.' },
  { label: 'Claymorphism', prompt: 'Inflated clay-like look with soft inner shadows and rounded forms.' },
  { label: 'Liquid Metal', prompt: 'Highly reflective chrome-like metallic surface.' },
  { label: 'Skeuomorphic', prompt: 'Old-school realistic look with gradients, textures, and deep shadows.' },
  { label: 'Retro Paper', prompt: 'Textured paper material with organic edges and subtle grain.' },
  { label: 'High Gloss', prompt: 'Plastic-like high-gloss finish with sharp reflections.' },
  { label: 'Matte Plastic', prompt: 'Soft matte plastic texture with very subtle highlights.' },
  { label: 'Brushed Aluminum', prompt: 'Horizontal metallic grain texture with anisotropic highlights.' },
  { label: 'Holographic', prompt: 'Iridescent color-shifting finish that reacts to "light".' },
  { label: 'Mesh Gradient', prompt: 'Background with soft, multi-colored mesh gradient textures.' },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [inspectorOpen, setInspectorOpen] = useState(true);
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);
  const [materialSearch, setMaterialSearch] = useState('');
  const [isMaterialDropdownOpen, setIsMaterialDropdownOpen] = useState(false);
  const [appTheme, setAppTheme] = useState<'light' | 'dark'>('light');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  const filteredMaterials = useMemo(() => 
    MATERIAL_OPTIONS.filter(m => m.label.toLowerCase().includes(materialSearch.toLowerCase())),
    [materialSearch]
  );

  // Sync theme with document element for Tailwind dark mode
  useEffect(() => {
    if (appTheme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [appTheme]);

  const getFullHtml = (interaction: GeneratedInteraction) => {
    return `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>${interaction.name}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&display=swap" rel="stylesheet">
    <style>
        body { 
            margin: 0; 
            display: flex; 
            align-items: center; 
            justify-content: center; 
            min-height: 100vh; 
            background: #ffffff; 
            font-family: 'Inter', sans-serif;
            overflow: hidden;
        }
        ${interaction.css}
    </style>
</head>
<body>
    <div id="root">
        ${interaction.html}
    </div>

    <script type="module">
        (function() {
            try {
                ${interaction.js}
            } catch (e) {
                console.error('Interaction Script Error:', e);
            }
        })();
    </script>
</body>
</html>`;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setAttachedImage({
          data: base64String,
          mimeType: file.type
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeAttachment = () => {
    setAttachedImage(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Interaction',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        variationOf: activeId || undefined,
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) setPrompt('');
      removeAttachment();
    } catch (error: any) {
      console.error("Generation failed:", error);
      alert(`Error: ${error.message || 'Failed to generate interaction.'}`);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleNewInteraction = () => {
    setActiveId(null);
    setPrompt('');
    removeAttachment();
  };

  return (
    <div className={`flex h-screen overflow-hidden font-sans relative transition-colors duration-300 ${appTheme === 'dark' ? 'bg-[#191919] text-gray-100' : 'bg-white text-gray-900'}`}>
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />

      {/* 1. Sidebar (Explorer) */}
      <aside className={`${sidebarOpen ? 'w-64' : 'w-0'} transition-all duration-300 flex flex-col border-r border-gray-100 dark:border-[#2f2f2f] bg-[#fbfbfa] dark:bg-[#202020] shrink-0 overflow-hidden z-10`}>
        <div className="p-4 flex items-center justify-between border-b border-gray-50 dark:border-[#2f2f2f] bg-white dark:bg-[#191919]">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 bg-black dark:bg-white rounded shadow-sm flex items-center justify-center">
              <span className="text-white dark:text-black text-[10px] font-bold">MN</span>
            </div>
            <span className="text-sm font-bold tracking-tight">MicroNotion</span>
          </div>
          <button onClick={() => setSidebarOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 p-1">
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M11 19l-7-7 7-7m8 14l-7-7 7-7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-2 notion-scrollbar">
          <button onClick={handleNewInteraction} className="w-full flex items-center gap-2 px-3 py-2 text-sm text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-[#2f2f2f] rounded-lg mb-6 transition-all group">
            <div className="w-5 h-5 flex items-center justify-center rounded border border-dashed border-gray-300 dark:border-[#444] text-gray-400 group-hover:border-gray-400 group-hover:text-gray-600 dark:group-hover:text-gray-200">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </div>
            <span className="font-medium">New Creation</span>
          </button>

          <div className="px-3 mb-2">
            <span className="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest">History</span>
          </div>
          <div className="space-y-0.5">
            {history.map(item => (
              <button
                key={item.id}
                onClick={() => setActiveId(item.id)}
                className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-all truncate flex items-center justify-between group ${activeId === item.id ? 'bg-gray-200 dark:bg-[#373737] text-gray-900 dark:text-white font-semibold shadow-sm' : 'text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-[#2f2f2f]'}`}
              >
                <span className="truncate">{item.name}</span>
                {item.hasImage && <div className="w-1.5 h-1.5 bg-blue-500 rounded-full shrink-0 ml-2"></div>}
              </button>
            ))}
          </div>
        </div>
      </aside>

      {/* 2. Main Workspace (Canvas) */}
      <main className="flex-1 flex flex-col min-w-0 relative z-0">
        <header className="h-12 border-b border-gray-100 dark:border-[#2f2f2f] flex items-center justify-between px-4 sticky top-0 bg-white/80 dark:bg-[#191919]/80 backdrop-blur-md z-20">
          <div className="flex items-center gap-4">
            {!sidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 p-1">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 6h16M4 12h16M4 18h16" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
            )}
            <div className="flex items-center text-[11px] font-mono text-gray-400 dark:text-gray-500 gap-1.5 uppercase tracking-wider">
              <span>Workspace</span>
              <span>/</span>
              <span className="text-black dark:text-white font-bold truncate max-w-[200px]">{activeInteraction?.name || 'Creation Lab'}</span>
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* Theme Toggle Button */}
             <button 
                onClick={() => setAppTheme(appTheme === 'light' ? 'dark' : 'light')}
                className="p-1.5 rounded-lg border border-gray-200 dark:border-[#2f2f2f] hover:bg-gray-100 dark:hover:bg-[#2f2f2f] transition-all text-gray-500 dark:text-gray-400"
                title={`Switch to ${appTheme === 'light' ? 'Dark' : 'Light'} Mode`}
              >
                {appTheme === 'light' ? (
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" strokeWidth="2"/></svg>
                ) : (
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707.707M12 5a7 7 0 100 14 7 7 0 000-14z" strokeWidth="2" strokeLinecap="round"/></svg>
                )}
              </button>

            {activeInteraction && (
              <>
                <div className="flex items-center gap-1 bg-gray-100 dark:bg-[#2f2f2f] p-0.5 rounded-lg border border-gray-200/50 dark:border-transparent shadow-sm">
                  <button
                    onClick={() => setViewMode('preview')}
                    className={`px-3 py-1 text-[11px] rounded-md transition-all font-bold ${viewMode === 'preview' ? 'bg-white dark:bg-[#444] shadow-sm text-black dark:text-white' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'}`}
                  >Preview</button>
                  <button
                    onClick={() => setViewMode('code')}
                    className={`px-3 py-1 text-[11px] rounded-md transition-all font-bold ${viewMode === 'code' ? 'bg-white dark:bg-[#444] shadow-sm text-black dark:text-white' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'}`}
                  >Full Code</button>
                </div>
                {!inspectorOpen && (
                   <button onClick={() => setInspectorOpen(true)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 p-1">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                   </button>
                )}
              </>
            )}
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-6 md:p-12 max-w-5xl mx-auto w-full notion-scrollbar">
          {!activeInteraction ? (
            <div className="h-full flex flex-col items-center justify-center text-center space-y-12 animate-in fade-in duration-700">
              <div className="w-20 h-20 bg-[#fbfbfa] dark:bg-[#202020] rounded-[32px] flex items-center justify-center text-4xl shadow-inner border border-gray-100 dark:border-[#2f2f2f]">✨</div>
              <div className="space-y-4">
                <h1 className="text-5xl font-black tracking-tighter text-black dark:text-white">Interaction Studio</h1>
                <p className="text-gray-400 dark:text-gray-500 text-lg max-w-lg mx-auto font-medium leading-relaxed">Describe a micro-interaction. Refine every detail visually.</p>
              </div>

              <div className="w-full max-w-xl space-y-6 pt-6">
                <div className={`relative group shadow-2xl rounded-3xl p-2 border flex items-center transition-all focus-within:ring-8 focus-within:ring-gray-50 dark:focus-within:ring-white/5 ${appTheme === 'dark' ? 'bg-[#252525] border-[#2f2f2f]' : 'bg-white border-gray-100'}`}>
                  <div className="flex items-center shrink-0">
                    <button 
                      onClick={() => fileInputRef.current?.click()}
                      className={`ml-2 p-4 rounded-2xl transition-all ${attachedImage ? 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 shadow-sm' : 'text-gray-300 dark:text-gray-600 hover:text-gray-600 dark:hover:text-gray-300'}`}
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                    </button>
                  </div>
                  <input
                    type="text"
                    placeholder="E.g., 'Modern glass switch with bounce'..."
                    className="flex-1 px-4 py-6 rounded-2xl border-none focus:outline-none bg-transparent text-xl font-medium placeholder-gray-200 dark:placeholder-gray-700"
                    value={prompt}
                    onChange={(e) => setPrompt(e.target.value)}
                    onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
                  />
                  <div className="flex items-center shrink-0 pr-1">
                    <button
                      onClick={() => handleGenerate()}
                      disabled={isGenerating || (!prompt.trim() && !attachedImage)}
                      className="p-5 bg-black dark:bg-white text-white dark:text-black rounded-2xl disabled:opacity-30 hover:bg-gray-800 dark:hover:bg-gray-200 transition-all active:scale-95 shadow-xl flex items-center justify-center"
                    >
                      {isGenerating ? (
                        <svg className="animate-spin h-6 w-6" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" /><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" /></svg>
                      ) : (
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7m0 0l-7 7m7-7H3" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                      )}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : (
            <div className="space-y-12 animate-in fade-in duration-500 pb-32">
              <div className="flex items-end justify-between gap-8 flex-wrap">
                <div className="max-w-2xl space-y-3">
                  <h1 className="text-4xl font-black tracking-tight leading-none text-black dark:text-white">{activeInteraction.name}</h1>
                  <p className="text-gray-400 dark:text-gray-500 text-sm italic font-medium">"{activeInteraction.prompt}"</p>
                </div>
              </div>

              {viewMode === 'preview' ? (
                <div className="relative rounded-[40px] overflow-hidden shadow-[0_40px_80px_-20px_rgba(0,0,0,0.1)] border border-gray-100 dark:border-[#2f2f2f] bg-white dark:bg-[#111]">
                  <InteractionPreview interaction={activeInteraction} />
                </div>
              ) : (
                <div className="space-y-6 animate-in slide-in-from-bottom-6 duration-400">
                  <CodeBlock language="Single-File Component" code={getFullHtml(activeInteraction)} />
                </div>
              )}
            </div>
          )}
        </div>

        {isGenerating && (
          <div className="absolute inset-0 bg-white/60 dark:bg-[#191919]/60 backdrop-blur-xl z-50 flex items-center justify-center">
             <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-gray-100 dark:border-[#2f2f2f] border-t-black dark:border-t-white rounded-full animate-spin"></div>
                <p className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest">Applying Changes</p>
             </div>
          </div>
        )}
      </main>

      {/* 3. Right Sidebar (Inspector) */}
      {activeInteraction && (
        <aside className={`${inspectorOpen ? 'w-[320px]' : 'w-0'} transition-all duration-300 border-l border-gray-100 dark:border-[#2f2f2f] bg-[#fbfbfa] dark:bg-[#202020] flex flex-col shrink-0 overflow-hidden z-10`}>
          <div className="p-4 flex items-center justify-between border-b border-gray-50 dark:border-[#2f2f2f] bg-white dark:bg-[#191919]">
            <span className="text-[11px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest">Inspector</span>
            <button onClick={() => setInspectorOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 p-1">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 5l7 7m0 0l-7 7m7-7H3" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" transform="scale(-1,1) translate(-24,0)"/></svg>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 space-y-8 notion-scrollbar pb-10">
            {/* Manual Chat Refinement */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Manual Refinement</h4>
              <div className="relative group">
                <textarea
                  id="refinement-input-inspector"
                  placeholder="Describe changes (e.g. 'Add a pulsing effect')..."
                  className="w-full px-3 py-3 bg-white dark:bg-[#252525] border border-gray-200 dark:border-[#2f2f2f] rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-black/5 dark:focus:ring-white/5 min-h-[80px] resize-none notion-scrollbar dark:text-gray-200"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      const val = (e.target as HTMLTextAreaElement).value;
                      handleGenerate(val);
                      (e.target as HTMLTextAreaElement).value = '';
                    }
                  }}
                />
                <p className="text-[9px] text-gray-400 dark:text-gray-600 mt-1 font-medium">Press Enter to apply</p>
              </div>
            </section>

            {/* Component Theme Logic (Light/Dark mode for the component itself) */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Component Logic Theme</h4>
              <div className="grid grid-cols-2 gap-2 p-1 bg-gray-100 dark:bg-[#2f2f2f] rounded-xl">
                 <button 
                  onClick={() => handleGenerate('Switch the component to Light Mode style (light backgrounds, dark text).')}
                  className="flex items-center justify-center gap-2 py-2 px-3 bg-white dark:bg-[#373737] shadow-sm rounded-lg text-[11px] font-bold hover:bg-white/80 dark:hover:bg-[#444] transition-all border border-gray-200 dark:border-transparent text-gray-700 dark:text-gray-200"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707.707M12 5a7 7 0 100 14 7 7 0 000-14z" strokeWidth="2" strokeLinecap="round"/></svg>
                  Light
                </button>
                 <button 
                  onClick={() => handleGenerate('Switch the component to Dark Mode style (dark backgrounds, light text).')}
                  className="flex items-center justify-center gap-2 py-2 px-3 bg-gray-900 text-white rounded-lg text-[11px] font-bold hover:bg-black transition-all shadow-sm"
                >
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z" strokeWidth="2" strokeLinecap="round"/></svg>
                  Dark
                </button>
              </div>
            </section>

            {/* Visual Styles */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Visual Style</h4>

              <div className="space-y-2">
                <label className="text-xs font-semibold text-gray-500 dark:text-gray-400">Theme Color</label>
                <div className="flex flex-wrap gap-2">
                  {[
                    {name: 'Obsidian', color: '#000000'},
                    {name: 'Iris', color: '#6366f1'},
                    {name: 'Emerald', color: '#10b981'},
                    {name: 'Rose', color: '#f43f5e'},
                    {name: 'Amber', color: '#f59e0b'},
                    {name: 'Violet', color: '#8b5cf6'}
                  ].map(c => (
                    <button 
                      key={c.name}
                      onClick={() => handleGenerate(`Change the primary theme color to ${c.color} (${c.name}).`)}
                      className="w-6 h-6 rounded-full border border-gray-200 dark:border-[#444] transition-transform hover:scale-110 active:scale-95 shadow-sm"
                      style={{backgroundColor: c.color}}
                      title={c.name}
                    />
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-semibold text-gray-500 dark:text-gray-400">Corner Radius</label>
                <div className="grid grid-cols-3 gap-1 p-1 bg-gray-100 dark:bg-[#2f2f2f] rounded-lg">
                  {['Sharp', 'Medium', 'Round'].map(r => (
                    <button 
                      key={r}
                      onClick={() => handleGenerate(`Set the border-radius to ${r === 'Sharp' ? '0px' : r === 'Medium' ? '12px' : '999px'}.`)}
                      className="text-[10px] font-bold py-1.5 px-2 rounded-md hover:bg-white dark:hover:bg-[#444] hover:shadow-sm dark:text-gray-300 dark:hover:text-white transition-all"
                    >{r}</button>
                  ))}
                </div>
              </div>
            </section>

            {/* Material Section - Searchable Dropdown */}
            <section className="space-y-4 relative">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Materiality</h4>
              <div className="relative">
                <div className="flex items-center bg-white dark:bg-[#252525] border border-gray-200 dark:border-[#2f2f2f] rounded-xl px-3 py-2.5 shadow-sm focus-within:ring-2 focus-within:ring-black/5 dark:focus-within:ring-white/5 transition-all">
                  <svg className="w-3.5 h-3.5 text-gray-400 dark:text-gray-600 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2.5"/></svg>
                  <input 
                    type="text" 
                    placeholder="Search materials..." 
                    className="w-full text-[11px] font-bold bg-transparent outline-none text-gray-700 dark:text-gray-200"
                    value={materialSearch}
                    onChange={(e) => {
                      setMaterialSearch(e.target.value);
                      setIsMaterialDropdownOpen(true);
                    }}
                    onFocus={() => setIsMaterialDropdownOpen(true)}
                  />
                  {materialSearch && (
                    <button onClick={() => setMaterialSearch('')} className="text-gray-300 dark:text-gray-600 hover:text-gray-500">
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3"/></svg>
                    </button>
                  )}
                </div>

                {isMaterialDropdownOpen && (
                  <div className="absolute top-full left-0 right-0 mt-1 bg-white dark:bg-[#252525] border border-gray-100 dark:border-[#2f2f2f] rounded-xl shadow-2xl z-30 max-h-[200px] overflow-y-auto notion-scrollbar animate-in fade-in slide-in-from-top-2 duration-200">
                    {filteredMaterials.length > 0 ? (
                      filteredMaterials.map(m => (
                        <button
                          key={m.label}
                          onClick={() => {
                            handleGenerate(m.prompt);
                            setIsMaterialDropdownOpen(false);
                            setMaterialSearch('');
