                          className="w-full text-left px-4 py-3 text-[11px] font-bold text-gray-600 dark:text-gray-400 hover:bg-gray-50 dark:hover:bg-[#2f2f2f] hover:text-black dark:hover:text-white border-b border-gray-50 dark:border-[#2f2f2f] last:border-0 transition-colors"
