                {isMaterialDropdownOpen && (
                  <div className="fixed inset-0 z-20" onClick={() => setIsMaterialDropdownOpen(false)} />
                )}
              </div>
            </section>

            {/* Typography Section */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Typography</h4>
              <div className="flex items-center justify-between">
                <span className="text-xs font-semibold text-gray-500 dark:text-gray-400">Font Size</span>
                <div className="flex gap-1">
                  {['S', 'M', 'L'].map(sz => (
                    <button 
                      key={sz}
                      onClick={() => handleGenerate(`Adjust text sizing to ${sz === 'S' ? 'small/compact' : sz === 'M' ? 'standard' : 'large/hero'}.`)}
                      className="w-7 h-7 flex items-center justify-center bg-white dark:bg-[#252525] border border-gray-200 dark:border-[#2f2f2f] rounded-md text-[10px] font-bold hover:border-black dark:hover:border-white shadow-sm dark:text-gray-300"
                    >{sz}</button>
                  ))}
                </div>
              </div>
            </section>

            {/* Physics Section */}
            <section className="space-y-4">
              <h4 className="text-[10px] font-black text-gray-300 dark:text-gray-600 uppercase tracking-widest">Motion & Physics</h4>
              <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <label className="text-xs font-semibold text-gray-500 dark:text-gray-400">Speed</label>
                    <span className="text-[9px] font-bold text-gray-400 dark:text-gray-600 uppercase tracking-tighter">Snappy → Fluid</span>
                  </div>
                  <input 
                  type="range" 
                  min="1" max="10" 
                  className="w-full accent-black dark:accent-white h-1 bg-gray-200 dark:bg-[#2f2f2f] rounded-lg appearance-none cursor-pointer"
                  onChange={(e) => {
                    const val = parseInt(e.target.value);
                    if (val < 4) handleGenerate('Make the transitions much faster and snappier.');
                    else if (val > 7) handleGenerate('Make the transitions very slow and graceful.');
                    else handleGenerate('Set the transition speed to a balanced fluid pace.');
                  }}
                  />
              </div>
              <button 
                onClick={() => handleGenerate('Add a subtle "spring" bounce effect to all hover and active states.')}
                className="w-full py-2.5 bg-gray-900 dark:bg-white text-white dark:text-black rounded-xl text-[11px] font-bold hover:bg-black dark:hover:bg-gray-100 transition-all shadow-lg active:scale-95"
              >
                Apply Spring Physics
              </button>
            </section>
          </div>

          <div className="p-4 bg-white dark:bg-[#191919] border-t border-gray-50 dark:border-[#2f2f2f] mt-auto">
             <div className="bg-blue-50/50 dark:bg-blue-900/10 rounded-xl p-3 border border-blue-100/50 dark:border-blue-900/20">
                <p className="text-[9px] font-bold text-blue-400 dark:text-blue-500 uppercase tracking-wider mb-1">AI Reasoning</p>
                <p className="text-[10px] text-blue-600 dark:text-blue-400 leading-tight">Gemini applies your constraints while maintaining structural design integrity.</p>
             </div>
          </div>
        </aside>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const MATERIAL_OPTIONS = [
  { label: 'Glassmorphism', prompt: 'Make it a glass container with backdrop blur and white border highlight.' },
  { label: 'Neumorphic', prompt: 'Apply a soft neumorphic look with inner and outer shadows.' },
  { label: 'Flat Solid', prompt: 'Clean solid fill with a 1px crisp border.' },
  { label: 'Frosted Glass', prompt: 'Heavy frosted glass effect with high blur and subtle noise.' },
  { label: 'Claymorphism', prompt: 'Inflated clay-like look with soft inner shadows and rounded forms.' },
  { label: 'Liquid Metal', prompt: 'Highly reflective chrome-like metallic surface.' },
  { label: 'Skeuomorphic', prompt: 'Realistic look with deep gradients and tactile textures.' },
  { label: 'Holographic', prompt: 'Iridescent color-shifting finish that reacts to simulated light.' },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [inspectorOpen, setInspectorOpen] = useState(true);
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);
  const [materialSearch, setMaterialSearch] = useState('');
  const [appTheme, setAppTheme] = useState<'light' | 'dark'>('dark');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  const filteredMaterials = useMemo(() => 
    MATERIAL_OPTIONS.filter(m => m.label.toLowerCase().includes(materialSearch.toLowerCase())),
    [materialSearch]
  );

  useEffect(() => {
    document.documentElement.classList.toggle('dark', appTheme === 'dark');
  }, [appTheme]);

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Untitled Concept',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) setPrompt('');
      setAttachedImage(null);
    } catch (error: any) {
      console.error("Generation failed:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden font-sans bg-[#fcfcfc] dark:bg-studio-black text-gray-900 dark:text-gray-100 selection:bg-studio-accent selection:text-white">
      <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
        const file = e.target.files?.[0];
        if (file) {
          const reader = new FileReader();
          reader.onloadend = () => setAttachedImage({ data: (reader.result as string).split(',')[1], mimeType: file.type });
          reader.readAsDataURL(file);
        }
      }} />

      {/* Dynamic Sidebar Overlay */}
      <AnimatePresence>
        {sidebarOpen && (
          <motion.aside
            initial={{ x: -300, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: -300, opacity: 0 }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed left-6 top-6 bottom-6 w-72 z-40 flex flex-col gap-4"
          >
            <div className="flex-1 studio-blur bg-white/70 dark:bg-studio-charcoal/80 border border-black/5 dark:border-white/10 rounded-[32px] shadow-2xl overflow-hidden flex flex-col p-6">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-studio-accent rounded-2xl flex items-center justify-center shadow-lg shadow-studio-accent/20">
                    <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  </div>
                  <span className="text-lg font-black tracking-tight italic">STUDIO</span>
                </div>
                <button onClick={() => setSidebarOpen(false)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-all">
                   <svg className="w-5 h-5 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                </button>
              </div>

              <button 
                onClick={() => { setActiveId(null); setPrompt(''); }}
                className="w-full flex items-center justify-center gap-2 py-3 bg-studio-accent text-white rounded-2xl font-bold text-sm shadow-xl shadow-studio-accent/30 hover:scale-[1.02] active:scale-95 transition-all mb-8"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round"/></svg>
                New Concept
              </button>

              <div className="flex-1 overflow-y-auto space-y-2 notion-scrollbar pr-2">
                <p className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] mb-4 pl-2">Timeline</p>
                {history.map(item => (
                  <motion.button
                    layout
                    key={item.id}
                    onClick={() => setActiveId(item.id)}
                    className={`w-full text-left px-4 py-3 rounded-2xl text-sm transition-all flex items-center justify-between group ${activeId === item.id ? 'bg-white dark:bg-studio-accent text-black dark:text-white shadow-lg font-bold' : 'hover:bg-black/5 dark:hover:bg-white/5 opacity-60 hover:opacity-100'}`}
                  >
                    <span className="truncate">{item.name}</span>
                    <div className={`w-1.5 h-1.5 rounded-full ${item.hasImage ? 'bg-studio-cyan' : 'opacity-0'}`} />
                  </motion.button>
                ))}
              </div>
            </div>
          </motion.aside>
        )}
      </AnimatePresence>

      {/* Main Experience */}
      <main className="flex-1 relative flex flex-col items-center justify-center">
        {/* Floating Top Controls */}
        <nav className="absolute top-8 left-0 right-0 z-30 flex justify-center pointer-events-none">
          <div className="flex items-center gap-2 studio-blur bg-white/60 dark:bg-studio-charcoal/60 p-2 rounded-2xl border border-black/5 dark:border-white/10 shadow-xl pointer-events-auto">
            {!sidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 6h16M4 12h16M4 18h16" strokeWidth="2.5" strokeLinecap="round"/></svg>
              </button>
            )}
            <div className="h-4 w-px bg-black/10 dark:bg-white/10 mx-1" />
            <button onClick={() => setAppTheme(appTheme === 'light' ? 'dark' : 'light')} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-all">
              {appTheme === 'light' ? <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" strokeWidth="2"/></svg> : <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 3v1m0 16v1m9-9h-1M4 12H3m15.364-6.364l-.707.707M6.343 17.657l-.707.707m12.728 0l-.707-.707M6.343 6.343l-.707.707M12 5a7 7 0 100 14 7 7 0 000-14z" strokeWidth="2"/></svg>}
            </button>
            {activeInteraction && (
              <>
                <div className="h-4 w-px bg-black/10 dark:bg-white/10 mx-1" />
                <div className="flex bg-black/5 dark:bg-white/5 p-1 rounded-xl">
                  <button onClick={() => setViewMode('preview')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'preview' ? 'bg-white dark:bg-studio-accent shadow-sm' : 'opacity-40 hover:opacity-100'}`}>Visual</button>
                  <button onClick={() => setViewMode('code')} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${viewMode === 'code' ? 'bg-white dark:bg-studio-accent shadow-sm' : 'opacity-40 hover:opacity-100'}`}>Source</button>
                </div>
              </>
            )}
            {!inspectorOpen && activeInteraction && (
              <button onClick={() => setInspectorOpen(true)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-all">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10" strokeWidth="2"/></svg>
              </button>
            )}
          </div>
        </nav>

        {/* Central Stage */}
        <div className="w-full h-full flex items-center justify-center p-8 md:p-24 overflow-hidden relative">
          <AnimatePresence mode="wait">
            {!activeInteraction ? (
              <motion.div 
                key="empty"
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 1.05 }}
                className="max-w-2xl w-full text-center space-y-12"
              >
                <div className="space-y-4">
                  <h1 className="text-7xl font-black tracking-tight leading-[0.9] text-transparent bg-clip-text bg-gradient-to-br from-gray-900 to-gray-400 dark:from-white dark:to-studio-accent">
                    Visualize <br/> the Invisible.
                  </h1>
                  <p className="text-xl text-gray-500 dark:text-gray-400 font-medium italic">High-fidelity interaction design, powered by Gemini.</p>
                </div>

                <div className="relative group">
                  <div className="absolute -inset-1 bg-gradient-to-r from-studio-accent to-studio-cyan rounded-[32px] blur opacity-25 group-focus-within:opacity-75 transition-all duration-500" />
                  <div className="relative studio-blur bg-white/80 dark:bg-studio-charcoal/80 border border-black/5 dark:border-white/10 rounded-[32px] p-2 flex items-center gap-2">
                    <button onClick={() => fileInputRef.current?.click()} className={`p-4 rounded-2xl transition-all ${attachedImage ? 'bg-studio-cyan text-white' : 'text-gray-400 hover:text-studio-accent'}`}>
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6" strokeWidth="2"/></svg>
                    </button>
                    <input 
                      type="text" 
                      placeholder="E.g., 'A fluid liquid-metal slider'..." 
                      className="flex-1 bg-transparent border-none outline-none px-4 py-4 text-xl font-medium placeholder:text-gray-300 dark:placeholder:text-gray-600"
                      value={prompt}
                      onChange={(e) => setPrompt(e.target.value)}
                      onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
                    />
                    <button 
                      onClick={() => handleGenerate()}
                      disabled={isGenerating}
                      className="w-16 h-16 bg-studio-accent text-white rounded-[24px] shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center disabled:opacity-20"
                    >
                      {isGenerating ? <div className="w-6 h-6 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M14 5l7 7m0 0l-7 7m7-7H3" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>}
                    </button>
                  </div>
                </div>
              </motion.div>
            ) : (
              <motion.div 
                key="active"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                className="w-full h-full flex flex-col gap-8"
              >
                <div className="flex-1 rounded-[48px] overflow-hidden shadow-2xl border border-black/5 dark:border-white/10 relative group">
                  {viewMode === 'preview' ? (
                    <InteractionPreview interaction={activeInteraction} />
                  ) : (
                    <div className="h-full bg-studio-charcoal p-8 overflow-y-auto notion-scrollbar">
                       <CodeBlock language="React / Vanilla" code={activeInteraction.html + '\n' + activeInteraction.css} />
                    </div>
                  )}
                  {isGenerating && (
                    <div className="absolute inset-0 bg-white/20 dark:bg-studio-black/20 backdrop-blur-md z-10 flex items-center justify-center">
                       <div className="flex flex-col items-center gap-4">
                          <div className="w-16 h-16 border-4 border-studio-accent/20 border-t-studio-accent rounded-full animate-spin" />
                          <p className="text-xs font-black uppercase tracking-widest text-studio-accent animate-pulse">Evolving Reality...</p>
                       </div>
                    </div>
                  )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </main>

      {/* Dynamic Inspector Overlay */}
      <AnimatePresence>
        {activeInteraction && inspectorOpen && (
          <motion.aside
            initial={{ x: 340, opacity: 0 }}
            animate={{ x: 0, opacity: 1 }}
            exit={{ x: 340, opacity: 0 }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed right-6 top-6 bottom-6 w-[320px] z-40 flex flex-col gap-4"
          >
            <div className="flex-1 studio-blur bg-white/70 dark:bg-studio-charcoal/80 border border-black/5 dark:border-white/10 rounded-[32px] shadow-2xl overflow-hidden flex flex-col p-6">
              <div className="flex items-center justify-between mb-8">
                <span className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em]">Configuration</span>
                <button onClick={() => setInspectorOpen(false)} className="p-2 hover:bg-black/5 dark:hover:bg-white/5 rounded-xl transition-all">
                   <svg className="w-5 h-5 opacity-50" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                </button>
              </div>

              <div className="flex-1 overflow-y-auto space-y-8 notion-scrollbar pr-2">
                <section className="space-y-4">
                  <div className="p-4 bg-white/50 dark:bg-black/20 rounded-2xl border border-black/5 dark:border-white/5 space-y-3">
                    <label className="text-xs font-bold opacity-40 uppercase tracking-wider block">Refine with AI</label>
                    <textarea 
                      placeholder="Add logic, effects, or styles..."
                      className="w-full bg-transparent border-none outline-none text-sm font-medium resize-none min-h-[80px]"
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' && !e.shiftKey) {
                          e.preventDefault();
                          handleGenerate(e.currentTarget.value);
                          e.currentTarget.value = '';
                        }
                      }}
                    />
                    <p className="text-[9px] opacity-30 font-bold">Press Enter to dispatch update</p>
                  </div>
                </section>

                <section className="space-y-4">
                  <label className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] block">Materiality</label>
                  <div className="grid grid-cols-2 gap-2">
                    {MATERIAL_OPTIONS.map(m => (
                      <button 
                        key={m.label}
                        onClick={() => handleGenerate(m.prompt)}
                        className="p-3 text-[10px] font-bold text-center bg-black/5 dark:bg-white/5 border border-transparent hover:border-studio-accent rounded-xl transition-all"
                      >{m.label}</button>
                    ))}
                  </div>
                </section>

                <section className="space-y-4">
                   <label className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] block">Chromatic Theme</label>
                   <div className="flex flex-wrap gap-2">
                    {[
                      {name: 'Electric', color: '#a855f7'},
                      {name: 'Cyber', color: '#06b6d4'},
                      {name: 'Ruby', color: '#f43f5e'},
                      {name: 'Gold', color: '#eab308'},
                      {name: 'Obsidian', color: '#000000'},
                      {name: 'Ghost', color: '#e2e8f0'}
                    ].map(c => (
                      <button 
                        key={c.name}
                        onClick={() => handleGenerate(`Change primary theme color to ${c.color}.`)}
                        className="w-8 h-8 rounded-full shadow-lg border-2 border-white/20 hover:scale-110 active:scale-90 transition-all"
                        style={{ backgroundColor: c.color }}
                      />
                    ))}
                   </div>
                </section>

                <section className="space-y-4">
                  <label className="text-[10px] font-black opacity-30 uppercase tracking-[0.2em] block">Motion Physics</label>
                  <div className="space-y-3">
                    <button 
                      onClick={() => handleGenerate('Add high-elasticity spring physics to all transitions.')}
                      className="w-full py-3 bg-studio-accent/10 text-studio-accent border border-studio-accent/20 rounded-2xl text-[11px] font-black uppercase tracking-widest hover:bg-studio-accent hover:text-white transition-all"
                    >Apply Elasticity</button>
                    <div className="flex items-center justify-between text-[10px] font-bold opacity-50">
                      <span>Snappy</span>
                      <span>Fluid</span>
                    </div>
                    <input 
                      type="range" min="1" max="10" 
                      className="w-full accent-studio-accent"
                      onChange={(e) => {
                        const v = parseInt(e.target.value);
                        if (v < 4) handleGenerate('Optimize for snappy, instant performance.');
                        else if (v > 7) handleGenerate('Optimize for slow, cinematic fluidity.');
                        else handleGenerate('Balance speed and grace for natural feel.');
                      }}
                    />
                  </div>
                </section>
              </div>
            </div>
          </motion.aside>
        )}
      </AnimatePresence>
    </div>
  );
};

export default App;

