import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the component (e.g., 'Modern Glass Toggle')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Include unique IDs for JS hooks.",
    },
    css: {
      type: Type.STRING,
      description: "Standard CSS for all styling. DO NOT use Tailwind classes in HTML; put all styling here to ensure portability and high fidelity.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for interactivity. Implement tactile feedback (hover/click) and smooth motion.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a Lead Design Engineer for a high-end creative studio like Portfolite or Linear.
    Your specialty is creating cinematic, hyper-realistic web micro-interactions.

    AESTHETIC PROTOCOL:
    1. HIGH-END CONTRAST: Use white on pure black or deep charcoal. Use very subtle opacity variations (white/10, white/30).
    2. DEPTH & LIGHT: Use 1px inner borders (highlights) and multi-layered soft box-shadows.
    3. FLUIDITY: All transitions must use cubic-bezier(0.16, 1, 0.3, 1).
    4. NO BULK: Avoid bulky borders or aggressive rounding unless asked. Think "Sleek" and "Professional".
    5. PORTABILITY: Write everything in pure CSS. DO NOT use Tailwind classes in the HTML.

    TECHNICAL:
    - SVGs: Use inline SVGs for all icons.
    - JS: Ensure every interaction has a physical "bounce" or "elastic" feel.
    - Canvas: The component should be self-contained and look amazing when centered in a frame.
  `;

  const userText = context 
    ? `Current Progress:
       ${context}

       Refinement: "${prompt}"

       Maintain the high-end creative studio aesthetic. Style exclusively via CSS field.`
    : `Create a cinematic micro-interaction: "${prompt}". Focus on premium dark-mode styling, smooth motion, and extreme attention to detail. Style exclusively via CSS field.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2500 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

