    text-[10px] font-black tracking-[0.35em] uppercase transition-all duration-300
    ${active 
      ? (appTheme === 'dark' ? 'text-white' : 'text-black') 
      : (appTheme === 'dark' ? 'text-white/30 hover:text-white/60' : 'text-black/30 hover:text-black/60')
    }
  `;

  return (
    <div className={`flex h-screen w-full overflow-hidden font-sans transition-colors duration-1000 ${appTheme === 'dark' ? 'text-white' : 'text-black'}`}>
