              <svg className="w-5 h-5" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"/></svg>
           </div>
           <span className="font-black tracking-tight text-xl uppercase italic">StudioLab</span>
        </div>

        <nav className="hidden lg:flex items-center gap-12 pointer-events-auto">
          <button onClick={() => setSidebarOpen(!sidebarOpen)} className={navItemClass(sidebarOpen)}>Archives</button>
          <button onClick={() => setInspectorOpen(!inspectorOpen)} className={navItemClass(inspectorOpen)}>Logic</button>
          <button className={navItemClass(false)}>Showcase</button>
          <button className={navItemClass(false)}>Connect</button>
        </nav>

        <div className="flex items-center gap-5 pointer-events-auto">
