            )}
          </button>
          <button className={`h-12 px-8 rounded-full text-[11px] font-black uppercase tracking-[0.2em] transition-all shadow-2xl active:scale-95 ${appTheme === 'dark' ? 'bg-white text-black hover:scale-105' : 'bg-black text-white hover:scale-105'}`}>
             New Concept
