import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A professional design concept name (e.g., 'Kinetic Core Switch')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Avoid using Tailwind classes. Use unique IDs.",
    },
    css: {
      type: Type.STRING,
      description: "Standard CSS. Implement cinematic depth, grain, and high-fidelity lighting.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JS for interactivity. Focus on physical realism and smooth easing.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are the Creative Director at a world-class design studio (think Portfolite, Linear, or Stripe). 
    Your mission is to produce cinematic, hyper-realistic web interactions.

    DESIGN PHILOSOPHY:
    1. ELEVATED MINIMALISM: Use pure blacks (#000), deep charcoals, and stark whites. Use opacity (white/0.1) for layered depth.
    2. SHADER AESTHETICS: When asked for "shaders" or "liquid", use SVG filter primitives (<filter><feTurbulence><feDisplacementMap>) or complex CSS radial/conic gradients to simulate high-end GPU effects.
    3. PRECISION: Use 1px borders, subtle inner shadows for highlights, and layered box-shadows for ultra-soft elevation.
    4. MOTION: Transitions MUST feel expensive. Use cubic-bezier(0.16, 1, 0.3, 1).
    5. THEME ADAPTIVE: Components should ideally look good in both dark and light modes, defaulting to the requested aesthetic.

    TECHNICAL RESTRAINTS:
    - NO TAILWIND in the HTML. Put all styles in the CSS field.
    - NO EXTERNAL ASSETS. Use SVGs for icons.
    - Vanilla JS only. Use mouse-tracking for "reactive" effects if it adds to the cinematic feel.
  `;

  const userText = context 
    ? `Design Iteration:
       ${context}

       Requested Evolution: "${prompt}"

       Maintain the premium creative studio aesthetic. Ensure high-fidelity rendering.`
    : `Create a cinematic design concept: "${prompt}". Focus on premium textures, sophisticated motion, and high-contrast professional styling.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 4000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

