import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, descriptive name for the interaction.",
    },
    html: {
      type: Type.STRING,
      description: "Clean HTML structure.",
    },
    css: {
      type: Type.STRING,
      description: "CSS styling. Prioritize clean typography, subtle borders, and professional color palettes.",
    },
    js: {
      type: Type.STRING,
      description: "Vanilla JavaScript for micro-interactions.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are an expert Frontend Engineer specializing in the Notion aesthetic: clean, functional, and minimalist.
    Your goal is to build micro-interactions that feel "native" to a professional productivity tool.

    AESTHETIC GUIDELINES:
    1. MINIMALISM: Use white, off-white, and shades of grey. Accents should be subtle (e.g., blue-500 for primary actions).
    2. TYPOGRAPHY: Prioritize Inter or system sans-serif. Clean weights (400, 600).
    3. SUBTLETY: Use very soft box-shadows (0 1px 2px rgba(0,0,0,0.05)) and 1px light borders.
    4. MOTION: Fast, purposeful transitions. Use cubic-bezier(0.4, 0, 0.2, 1) for a standard responsive feel.
    5. SHADERS: If a user specifically asks for "shaders", implement them via SVG filters or CSS gradients, but keep them clean and professional, not overwhelming.

    TECHNICAL:
    - Standard CSS only. DO NOT use Tailwind in the HTML output.
    - No external libraries.
    - Self-contained components.
  `;

  const userText = context 
    ? `Current Component:
       ${context}

       Refinement Task: "${prompt}"

       Update the component while strictly maintaining the Notion minimalist aesthetic.`
    : `Build a minimalist interaction: "${prompt}". Focus on clean lines, high utility, and professional styling.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

