import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const MATERIAL_OPTIONS = [
  { label: 'Glass', prompt: 'Clean glassmorphism with subtle borders.' },
  { label: 'Flat', prompt: 'Minimalist flat design, high utility.' },
  { label: 'Tactile', prompt: 'Soft skeuomorphism with gentle shadows.' },
  { label: 'Modern', prompt: 'Sleek, professional, dark-mode ready components.' },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [appTheme, setAppTheme] = useState<'light' | 'dark'>('light');
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  useEffect(() => {
    document.documentElement.className = appTheme;
  }, [appTheme]);

  const handleFileChange = (file: File) => {
    if (!file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      setAttachedImage({
        data: (reader.result as string).split(',')[1],
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (let i = 0; i < items.length; i++) {
      if (items[i].type.indexOf('image') !== -1) {
        const file = items[i].getAsFile();
        if (file) handleFileChange(file);
      }
    }
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Untitled Interaction',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) {
        setPrompt('');
        setAttachedImage(null);
      }
    } catch (error: any) {
      console.error("Generation failed:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-notion-light-bg dark:bg-notion-dark-bg text-notion-light-text dark:text-notion-dark-text overflow-hidden">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={(e) => e.target.files?.[0] && handleFileChange(e.target.files[0])} 
      />

      {/* Notion Sidebar */}
      <AnimatePresence initial={false}>
        {sidebarOpen && (
          <motion.aside
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: 240, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            className="h-full bg-notion-light-sidebar dark:bg-notion-dark-sidebar border-r border-notion-light-border dark:border-notion-dark-border flex flex-col overflow-hidden"
          >
