import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, descriptive name for the interaction.",
    },
    html: {
      type: Type.STRING,
      description: "Static HTML. If using React, this can be empty or just contain the wrapper.",
    },
    css: {
      type: Type.STRING,
      description: "CSS styling. Ensure components have a visible size and clean Notion aesthetics.",
    },
    js: {
      type: Type.STRING,
      description: "ESM JavaScript. Must handle mounting if using React.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are an expert Frontend Engineer specializing in the Notion aesthetic: clean, functional, and minimalist.

    AESTHETIC GUIDELINES:
    1. MINIMALISM: Use white, off-white, and shades of grey. Accents: blue-500.
    2. TYPOGRAPHY: Inter or system sans-serif.
    3. SUBTLETY: Soft shadows and 1px borders.

    SHADERS & REACT:
    You have access to '@paper-design/shaders-react'. 
    If you use React components (like MeshGradient), you MUST provide a complete mounting script in the 'js' field.

    MANDATORY REACT MOUNTING PATTERN:
    import React from 'react';
    import ReactDOM from 'react-dom/client';
    import { MeshGradient, FluidGradient, WaveShader, NoiseShader, SpiralShader } from '@paper-design/shaders-react';

    const App = () => {
      // Your component logic here
      return <MeshGradient colors={['#F5F5F7', '#E5E5E7', '#D1D1D6']} />;
    };

    const container = document.getElementById('interaction-root');
    if (container) {
      const root = ReactDOM.createRoot(container);
      root.render(<App />);
    }

    TECHNICAL RULES:
    - NO TAILWIND in the 'html' or 'css' fields.
    - If the interaction is Vanilla JS (no React), just manipulate the DOM directly.
    - Ensure everything has a specific width/height (usually 100% for the root) so it's visible.
  `;

  const userText = context 
    ? `Current Component:
       ${context}

       Refinement Task: "${prompt}"

       Update the component. If using shaders, ensure the mounting logic is complete and error-free.`
    : `Build a minimalist interaction: "${prompt}". Focus on clean lines and professional styling. If appropriate, use @paper-design/shaders-react with a full React mount script.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2500 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};

