                <span className="truncate">Design Workspace</span>
              </div>
              <button onClick={() => setSidebarOpen(false)} className="opacity-0 group-hover:opacity-100 p-1 hover:bg-notion-light-hover dark:hover:bg-notion-dark-hover rounded transition-all">
