            "react": "https://esm.sh/react@19.0.0",
            "react/": "https://esm.sh/react@19.0.0/",
            "react-dom": "https://esm.sh/react-dom@19.0.0",
            "react-dom/": "https://esm.sh/react-dom@19.0.0/",
            "react-dom/client": "https://esm.sh/react-dom@19.0.0/client",
            "framer-motion": "https://esm.sh/framer-motion@11.11.11?external=react,react-dom",
            "three": "https://esm.sh/three@0.170.0",
            "@paper-design/shaders-react": "https://esm.sh/@paper-design/shaders-react?external=react,react-dom,three"
          }
        }
        </script>
        <style>
          * { box-sizing: border-box; }
          html, body { 
            margin: 0; padding: 0; width: 100%; height: 100%; 
            overflow: hidden; background: transparent; 
            font-family: "Inter", -apple-system, sans-serif;
            -webkit-font-smoothing: antialiased;
          }
          #error-display {
            position: fixed; inset: 0; background: rgba(255,255,255,0.98);
            color: #ff4444; padding: 30px; font-family: monospace;
            display: none; z-index: 10000; overflow: auto;
            font-size: 13px; line-height: 1.6;
            border: 2px solid #ff4444;
          }
          ${interaction.css}
        </style>
      </head>
      <body>
        ${interaction.html.includes('interaction-root') ? interaction.html : `<div id="interaction-root" style="width:100%; height:100%;">${interaction.html}</div>`}
        <div id="error-display"></div>
        <script type="module">
          const errBox = document.getElementById('error-display');
          const report = (e) => {
            errBox.style.display = 'block';
            const stack = e.stack || '';
            const msg = e.message || e;
            errBox.innerHTML = '<div style="font-weight:bold;margin-bottom:15px;font-size:16px;text-transform:uppercase;">Preview Runtime Error</div>' + 
                             '<div style="background:#fff1f1;padding:15px;border-radius:8px;border:1px solid #ffcccc;">' + msg + '</div>' +
                             '<pre style="margin-top:20px;opacity:0.7;font-size:11px;">' + stack + '</pre>';
          };

          window.onerror = (m, u, l, c, e) => report(e || m);
          window.onunhandledrejection = (e) => report(e.reason);

          try {
            ${interaction.js}
          } catch (e) {
            report(e);
          }
        </script>
      </body>
    </html>
  `, [interaction.id, interaction.html, interaction.css, interaction.js]);

  return (
    <div className="w-full h-full relative">
      <iframe
        key={interaction.id}
        srcDoc={srcDoc}
        title="Interaction Preview"
        className="w-full h-full border-none pointer-events-auto"
        sandbox="allow-scripts allow-modals allow-popups allow-same-origin"
      />
    </div>
  );
};

