import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A short, descriptive name for the interaction.",
    },
    html: {
      type: Type.STRING,
      description: "HTML structure. Must include <div id='interaction-root' style='width:100%; height:100%;'></div> for React rendering.",
    },
    css: {
      type: Type.STRING,
      description: "CSS styling. Minimalist Notion aesthetics. Use 'Inter' font.",
    },
    js: {
      type: Type.STRING,
      description: "ESM JavaScript module code. Must handle mounting to #interaction-root.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are an expert Lead Creative Technologist. Your goal is to build stunning micro-interactions in the Notion aesthetic.

    AESTHETIC:
    - Minimalist, professional, clean borders (1px #edece9), white/off-white bg.
    - Accents: blue-500 (#3b82f6).
    - Typography: "Inter", sans-serif.

    CRITICAL REACT 19 RULES:
    1. ALWAYS use the following import style:
       import React, { useState, useEffect, useRef, useMemo } from 'react';
       import ReactDOM from 'react-dom/client';
       import { motion, AnimatePresence } from 'framer-motion';
       import { MeshGradient, FluidGradient } from '@paper-design/shaders-react';

    2. Deduplication is key. DO NOT import from URLs in your 'js' field. Use plain library names (e.g., 'react', 'react-dom/client', 'framer-motion'). The environment's importmap handles the mapping.

    3. MOUNTING PATTERN:
       const App = () => { ... };
       const rootElement = document.getElementById('interaction-root');
       if (rootElement) {
         const root = ReactDOM.createRoot(rootElement);
         root.render(<App />);
       }

    4. SHADERS: If using MeshGradient, ensure it is wrapped in a container with dimensions.

    When an image is provided, analyze its layout, colors, and shadows to inform your design.
  `;

  const userText = context 
    ? `Current Component Context:\n${context}\n\nRefinement Request: "${prompt}"`
    : `New Project Request: "${prompt}"`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 4000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON.");
  }
};

