import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { generateInteraction } from './services/geminiService';
import { GeneratedInteraction, ImageAttachment } from './types';
import InteractionPreview from './components/InteractionPreview';
import CodeBlock from './components/CodeBlock';

const MATERIAL_OPTIONS = [
  { label: 'Notion Card', prompt: 'A clean, minimalist card with a subtle hover effect and breadcrumbs.' },
  { label: 'Liquid Toggle', prompt: 'A highly responsive toggle switch with elastic spring animations.' },
  { label: 'Glass Modal', prompt: 'A sleek glassmorphism modal with background blur and smooth entry.' },
  { label: 'Floating Menu', prompt: 'A vertical sidebar menu that expands with a bounce and active states.' },
];

const App: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [history, setHistory] = useState<GeneratedInteraction[]>([]);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<'preview' | 'code'>('preview');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [appTheme, setAppTheme] = useState<'light' | 'dark'>('light');
  const [attachedImage, setAttachedImage] = useState<ImageAttachment | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const activeInteraction = history.find(item => item.id === activeId);

  useEffect(() => {
    document.documentElement.className = appTheme;
  }, [appTheme]);

  const handleFileChange = (file: File) => {
    if (!file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      setAttachedImage({
        data: (reader.result as string).split(',')[1],
        mimeType: file.type
      });
    };
    reader.readAsDataURL(file);
  };

  const handlePaste = (e: React.ClipboardEvent) => {
    const items = e.clipboardData.items;
    for (let i = 0; i < items.length; i++) {
      if (items[i].type.indexOf('image') !== -1) {
        const file = items[i].getAsFile();
        if (file) handleFileChange(file);
      }
    }
  };

  const handleGenerate = async (refinementPrompt?: string) => {
    const targetPrompt = refinementPrompt || prompt;
    if (!targetPrompt.trim() && !attachedImage) return;

    setIsGenerating(true);
    try {
      const context = activeInteraction ? `HTML: ${activeInteraction.html}\nCSS: ${activeInteraction.css}\nJS: ${activeInteraction.js}` : undefined;
      const result = await generateInteraction(targetPrompt, context, attachedImage || undefined);

      const newInteraction: GeneratedInteraction = {
        id: Math.random().toString(36).substring(7),
        name: result.name || 'Untitled Interaction',
        prompt: targetPrompt,
        html: result.html,
        css: result.css,
        js: result.js,
        timestamp: Date.now(),
        hasImage: !!attachedImage
      };

      setHistory(prev => [newInteraction, ...prev]);
      setActiveId(newInteraction.id);
      if (!refinementPrompt) {
        setPrompt('');
        setAttachedImage(null);
      }
    } catch (error: any) {
      console.error("Generation failed:", error);
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-notion-light-bg dark:bg-notion-dark-bg text-notion-light-text dark:text-notion-dark-text overflow-hidden">
      <input 
        type="file" 
        ref={fileInputRef} 
        className="hidden" 
        accept="image/*" 
        onChange={(e) => e.target.files?.[0] && handleFileChange(e.target.files[0])} 
      />

      {/* Notion Sidebar */}
      <AnimatePresence initial={false}>
        {sidebarOpen && (
          <motion.aside
            initial={{ width: 0, opacity: 0 }}
            animate={{ width: 240, opacity: 1 }}
            exit={{ width: 0, opacity: 0 }}
            className="h-full bg-notion-light-sidebar dark:bg-notion-dark-sidebar border-r border-notion-light-border dark:border-notion-dark-border flex flex-col overflow-hidden"
          >
            <div className="p-4 flex items-center justify-between group">
              <div className="flex items-center gap-2 font-semibold truncate">
                <span className="w-5 h-5 bg-blue-500 rounded flex items-center justify-center text-white text-[10px]">L</span>
                <span className="truncate">Design Workspace</span>
              </div>
              <button onClick={() => setSidebarOpen(false)} className="opacity-0 group-hover:opacity-100 p-1 hover:bg-notion-light-hover dark:hover:bg-notion-dark-hover rounded transition-all">
                <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M15 18l-6-6 6-6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
              </button>
            </div>

            <div className="flex-1 overflow-y-auto px-2 notion-scrollbar">
              <div className="mb-4">
                <p className="text-[11px] font-bold opacity-40 uppercase tracking-wider px-2 py-2">Archives</p>
                {history.length === 0 && (
                   <p className="text-[11px] opacity-30 px-2 italic">No creations yet</p>
                )}
                {history.map(item => (
                  <button
                    key={item.id}
                    onClick={() => setActiveId(item.id)}
                    className={`w-full text-left px-3 py-1.5 rounded-md text-sm transition-all flex items-center gap-2 group ${activeId === item.id ? 'bg-white dark:bg-notion-dark-hover shadow-sm font-medium' : 'hover:bg-notion-light-hover dark:hover:bg-notion-dark-hover opacity-70 hover:opacity-100'}`}
                  >
                    <svg className="w-4 h-4 opacity-40" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" strokeWidth="2"/></svg>
                    <span className="truncate flex-1">{item.name}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="p-4 border-t border-notion-light-border dark:border-notion-dark-border space-y-2">
              <button 
                onClick={() => setAppTheme(appTheme === 'light' ? 'dark' : 'light')}
                className="w-full flex items-center gap-2 text-xs opacity-60 hover:opacity-100 px-2 py-1.5 hover:bg-notion-light-hover dark:hover:bg-notion-dark-hover rounded"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20.354 15.354A9 9 0 018.646 3.646 9.003 9.003 0 0012 21a9.003 9.003 0 008.354-5.646z" strokeWidth="2"/></svg>
                {appTheme === 'light' ? 'Dark Mode' : 'Light Mode'}
              </button>
            </div>
          </motion.aside>
        )}
