          <div className="flex items-center gap-3 text-sm">
            {!sidebarOpen && (
              <button onClick={() => setSidebarOpen(true)} className="p-1 hover:bg-notion-light-hover dark:hover:bg-notion-dark-hover rounded transition-all">
                <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M4 6h16M4 12h16M4 18h16" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
            )}
            <div className="flex items-center gap-1 opacity-40">
              <span>Studio</span>
              <span>/</span>
            </div>
            <span className="font-medium">{activeInteraction?.name || 'New Creation'}</span>
          </div>

          <div className="flex items-center gap-2">
             {activeId && (
               <div className="flex bg-notion-light-sidebar dark:bg-notion-dark-sidebar p-0.5 rounded border border-notion-light-border dark:border-notion-dark-border">
                  <button 
                    onClick={() => setViewMode('preview')} 
                    className={`px-3 py-1 text-xs rounded transition-all ${viewMode === 'preview' ? 'bg-white dark:bg-notion-dark-border shadow-sm font-semibold' : 'opacity-40 hover:opacity-100'}`}
                  >Preview</button>
                  <button 
                    onClick={() => setViewMode('code')} 
                    className={`px-3 py-1 text-xs rounded transition-all ${viewMode === 'code' ? 'bg-white dark:bg-notion-dark-border shadow-sm font-semibold' : 'opacity-40 hover:opacity-100'}`}
