export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { GenerationResponse, ImageAttachment } from "../types";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const GENERATION_SCHEMA = {
  type: Type.OBJECT,
  properties: {
    name: {
      type: Type.STRING,
      description: "A creative name for the component (e.g., 'Modern Glass Toggle')",
    },
    html: {
      type: Type.STRING,
      description: "Semantic HTML. Include unique IDs for JS hooks.",
    },
    css: {
      type: Type.STRING,
      description: "Standard CSS for all styling. Ensure high fidelity and portability. Do not use Tailwind in the output HTML/CSS.",
    },
    js: {
      type: Type.STRING,
      description: "ES Modules JavaScript. Use the most appropriate tool (CSS, WAAPI, or GSAP) based on complexity.",
    },
  },
  required: ["name", "html", "css", "js"],
};

export const generateInteraction = async (
  prompt: string,
  context?: string,
  image?: ImageAttachment
): Promise<GenerationResponse> => {
  const ai = getAI();
  const systemInstruction = `
    You are a world-class Lead Creative Technologist. Your specialty is "Hyper-Realistic Web Micro-Interactions".

    STRICT VISUAL RULES:
    1. PROMPT FAITHFULNESS: ONLY add "grain", "noise", "texture", or "paper" effects if the user explicitly asks for them.
    2. CLEAN BACKGROUNDS: The component should be centered on a clean background. Do NOT add complex environmental backgrounds unless explicitly requested.
    3. PORTABILITY: Style everything using standard CSS in the "css" field. Avoid using Tailwind classes in the HTML.
    4. FIDELITY: Use multi-layered shadows and 1px highlights to simulate depth.

    ANIMATION TECHNOLOGY STRATEGY:
    Select the most efficient tool for the specific request. Do not default to GSAP unless necessary.

    1. CSS (Transitions/Keyframes):
       - Use for: Simple hovers, focus states, button presses, basic toggles, loading spinners.
       - Example: transform: scale(0.98), opacity changes, background-color transitions.

    2. Web Animations API (WAAPI):
       - Use for: Orchestrated sequences, dynamic values calculated in JS, simple staggers, play/pause control.
       - Benefit: Native performance, lighter than GSAP, no external dependency overhead.

    3. GSAP (GreenSock):
       - Use for: Complex timelines, elastic/spring physics (e.g., 'elastic.out'), SVG path morphing, draggable elements, or highly complex "juicy" interactions.
       - Import: import gsap from 'gsap';

    TECHNICAL OUTPUT:
    - HTML: Semantic, clean, accessible.
    - CSS: Scoped and polished.
    - JS: ES Modules. Implement the logic using the selected strategy.
  `;

  const userText = context 
    ? `Current Component Code:
       ${context}

       Update Request: "${prompt}"

       Instructions: Analyze the complexity. If it's a simple change, stick to CSS/WAAPI. If it requires complex physics or timelines, use GSAP.`
    : `Build a micro-interaction: "${prompt}". 

       Decision Task: Analyze the requested complexity. 
       - If simple (e.g. "hover effect"), use CSS. 
       - If moderate (e.g. "sequence"), use WAAPI. 
       - If complex (e.g. "elastic bounce", "morph"), use GSAP.

       Style exclusively with CSS in the CSS block.`;

  const parts: any[] = [{ text: userText }];

  if (image) {
    parts.push({
      inlineData: {
        data: image.data,
        mimeType: image.mimeType
      }
    });
  }

  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: { parts },
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: GENERATION_SCHEMA,
      thinkingConfig: { thinkingBudget: 2000 }
    },
  });

  const text = response.text;
  if (!text) throw new Error("Empty response from AI");

  try {
    return JSON.parse(text.trim());
  } catch (e) {
    console.error("JSON Parse Error:", text);
    throw new Error("AI output was not valid JSON. Please try again.");
  }
};
